const fs = require("fs");
fs.mkdirSync("src/lib", { recursive: true });
fs.writeFileSync("src/app/page.tsx", "'use client';\nimport React from 'react';\nimport { useState, useEffect, useCallback, useRef } from 'react';\nimport PollCard from '@/components/PollCard';\nimport CreatePollModal from '@/components/CreatePollModal';\nimport CityMap from '@/components/CityMap';\nimport { subscribeToPolls, getUserVotes, castVote, createPoll, seedPolls, ensureAuth } from '@/lib/polls';\nimport { auth, db } from '@/lib/firebase';\nimport WhatsAppModal from '@/components/WhatsAppModal';\nimport AuthModal from '@/components/AuthModal';\nimport VotaCoin from '@/components/VotaCoin';\nimport { doc, getDoc, setDoc, onSnapshot } from 'firebase/firestore';\nimport { onAuthStateChanged, User, signOut } from 'firebase/auth';\n\nfunction fmt(n: number) {\n  if (n >= 1000000) return (n / 1000000).toFixed(1) + 'M';\n  if (n >= 1000) return (n / 1000).toFixed(1) + 'k';\n  return String(n);\n}\n\nfunction SaqueForm({ coins, email, uid, onSaque }: { coins: number; email: string; uid: string; onSaque: () => void }) {\n  const [pixKey, setPixKey] = useState('');\n  const [pixType, setPixType] = useState<'cpf' | 'email' | 'telefone' | 'aleatoria'>('email');\n  const [sent, setSent] = useState(false);\n  const [sending, setSending] = useState(false);\n\n  const handleSaque = async () => {\n    if (!pixKey.trim()) return;\n    setSending(true);\n    try {\n      const { doc, setDoc, serverTimestamp, updateDoc } = await import('firebase/firestore');\n      const { db } = await import('@/lib/firebase');\n      // Save withdrawal request to Firestore\n      const saqueId = `${uid}_${Date.now()}`;\n      await setDoc(doc(db, 'saques', saqueId), {\n        uid,\n        email,\n        coins,\n        valor: parseFloat((coins * 0.01).toFixed(2)),\n        pixKey: pixKey.trim(),\n        pixType,\n        status: 'pendente',\n        requestedAt: serverTimestamp(),\n      });\n      // Zero out coins\n      await updateDoc(doc(db, 'members', uid), { votaCoins: 0 });\n      setSent(true);\n      onSaque();\n    } catch (e) {\n      console.error('Saque error:', e);\n    }\n    setSending(false);\n  };\n\n  if (sent) return (\n    <div className=\"text-center py-4\">\n      <div className=\"text-3xl mb-2\">\ud83c\udf89</div>\n      <p className=\"text-sm font-black text-white\">Solicita\u00e7\u00e3o enviada!</p>\n      <p className=\"text-xs mt-1\" style={{ color: 'rgba(255,255,255,0.4)' }}>Voc\u00ea receber\u00e1 R${(coins * 0.01).toFixed(2)} via PIX em at\u00e9 48h \u00fateis.</p>\n    </div>\n  );\n\n  return (\n    <div className=\"space-y-3\">\n      <p className=\"text-xs font-bold\" style={{ color: 'rgba(255,255,255,0.5)' }}>\n        Valor a receber: <span style={{ color: '#4ADE80' }}>R${(coins * 0.01).toFixed(2)}</span>\n      </p>\n      {/* PIX type selector */}\n      <div className=\"grid grid-cols-4 gap-1\">\n        {(['cpf','email','telefone','aleatoria'] as const).map(t => (\n          <button key={t} onClick={() => setPixType(t)}\n            className=\"py-1.5 rounded-lg text-xs font-bold transition-all capitalize\"\n            style={{\n              background: pixType === t ? 'rgba(34,197,94,0.2)' : 'rgba(255,255,255,0.05)',\n              color: pixType === t ? '#4ADE80' : 'rgba(255,255,255,0.3)',\n              border: `1px solid ${pixType === t ? 'rgba(34,197,94,0.4)' : 'transparent'}`,\n            }}>\n            {t === 'aleatoria' ? 'Aleat.' : t}\n          </button>\n        ))}\n      </div>\n      <input\n        className=\"w-full rounded-xl px-4 py-3 text-sm text-white outline-none border\"\n        style={{ background: 'rgba(255,255,255,0.05)', borderColor: 'rgba(34,197,94,0.3)' }}\n        placeholder={\n          pixType === 'cpf' ? '000.000.000-00' :\n          pixType === 'email' ? 'seu@email.com' :\n          pixType === 'telefone' ? '(11) 99999-9999' :\n          'Chave aleat\u00f3ria'\n        }\n        value={pixKey}\n        onChange={e => setPixKey(e.target.value)}\n      />\n      <button\n        onClick={handleSaque}\n        disabled={!pixKey.trim() || sending}\n        className=\"w-full py-3 rounded-xl text-sm font-black transition-all\"\n        style={{\n          background: pixKey.trim() ? 'linear-gradient(90deg, #22C55E, #16A34A)' : 'rgba(255,255,255,0.07)',\n          color: pixKey.trim() ? 'white' : 'rgba(255,255,255,0.3)',\n        }}\n      >\n        {sending ? '\u23f3 Enviando...' : '\ud83d\udcb8 Solicitar saque via PIX'}\n      </button>\n      <p className=\"text-xs text-center\" style={{ color: 'rgba(255,255,255,0.2)' }}>\n        Seus coins ser\u00e3o zerados ap\u00f3s a solicita\u00e7\u00e3o\n      </p>\n    </div>\n  );\n}\n\nfunction HomeCore() {\n  const highlightSlug = typeof window !== 'undefined' ? sessionStorage.getItem('highlightSlug') || undefined : undefined;\n  const [polls, setPolls] = useState<any[]>([]);\n  const [votes, setVotes] = useState<Record<string, string>>({});\n  const [user, setUser] = useState<User | null>(null);\n  const [tab, setTab] = useState<'feed' | 'trending' | 'perfil'>('feed');\n  const [showCreate, setShowCreate] = useState(false);\n  const [showCity, setShowCity] = useState<string | null>(null);\n  const [streak, setStreak] = useState(0);\n  const [notif, setNotif] = useState<string | null>(null);\n  const [loading, setLoading] = useState(true);\n  const [city, setCity] = useState<string | null>(null);\n  const [search, setSearch] = useState('');\n  const [activeTag, setActiveTag] = useState<string | null>(null);\n  const [showWhatsApp, setShowWhatsApp] = useState(false);\n  const [showAuth, setShowAuth] = useState(false);\n  const [votaCoins, setVotaCoins] = useState(0);\n  const [highlightedId, setHighlightedId] = useState<string | null>(null);\n  const pollRefs = useRef<Record<string, HTMLDivElement | null>>({});\n  const hasVotedRef = useRef(false);\n  const [isSubscribed, setIsSubscribed] = useState(false);\n\n  // Auth\n  useEffect(() => {\n    const unsub = onAuthStateChanged(auth, async (u) => {\n      if (!u) {\n        const user = await ensureAuth();\n        setUser(user);\n      } else {\n        setUser(u);\n        // Listen to members doc in real-time so bonus/coins update immediately\n        if (!u.isAnonymous && u.email) {\n          const unsubMember = onSnapshot(doc(db, 'members', u.uid), snap => {\n            if (snap.exists()) {\n              const data = snap.data();\n              setVotaCoins(data?.votaCoins ?? 0);\n              if (data?.phone) setIsSubscribed(true);\n            }\n          }, e => console.error('[members] onSnapshot error:', e));\n          // Update last login metadata\n          setDoc(doc(db, 'members', u.uid), {\n            email: u.email,\n            displayName: u.displayName || null,\n            lastLogin: new Date().toISOString(),\n          }, { merge: true }).catch(() => null);\n          return unsubMember;\n        }\n      }\n    });\n    return unsub;\n  }, []);\n\n  // Geolocation\n  useEffect(() => {\n    fetch('https://freeipapi.com/api/json')\n      .then(r => r.json())\n      .then(d => setCity(d.cityName || null))\n      .catch(() => null);\n  }, []);\n\n  // Polls \u2014 wait for auth before subscribing\n  useEffect(() => {\n    if (!user) return;\n    seedPolls().catch(() => null);\n    const unsub = subscribeToPolls((p) => {\n      const sorted = [...p].sort((a, b) => {\n        if (a.pinned && !b.pinned) return -1;\n        if (!a.pinned && b.pinned) return 1;\n        return 0;\n      });\n      setPolls(sorted);\n      setLoading(false);\n    });\n    return unsub;\n  }, [user]);\n\n  // Scroll to highlighted poll \u2014 clear sessionStorage after scroll so votes don't re-trigger it\n  useEffect(() => {\n    if (!highlightSlug || polls.length === 0) return;\n    const poll = polls.find(p => p.slug === highlightSlug);\n    if (!poll) return;\n    setHighlightedId(poll.id);\n    setTimeout(() => {\n      const el = pollRefs.current[poll.id];\n      if (el) {\n        el.scrollIntoView({ behavior: 'smooth', block: 'center' });\n        sessionStorage.removeItem('highlightSlug');\n        setTimeout(() => setHighlightedId(null), 3000);\n      }\n    }, 500);\n  }, [highlightSlug, polls]);\n\n  // User votes + check subscription\n  useEffect(() => {\n    if (!user) return;\n    getUserVotes(user.uid).then(v => {\n      setVotes(v);\n      if (Object.keys(v).length > 0) hasVotedRef.current = true;\n    });\n    getDoc(doc(db, 'subscribers', user.uid)).then(snap => {\n      if (snap.exists()) setIsSubscribed(true);\n    }).catch(() => null);\n  }, [user]);\n\n  const showNotif = (msg: string) => {\n    setNotif(msg);\n    setTimeout(() => setNotif(null), 2500);\n  };\n\n  const handleVote = useCallback(async (id: string, choice: string) => {\n    if (!user || votes[id]) return;\n    setVotes(v => ({ ...v, [id]: choice }));\n    const ns = streak + 1;\n    setStreak(ns);\n    if (ns === 3) showNotif('\ud83d\udd25 3 seguidas! Voc\u00ea t\u00e1 no flow!');\n    else if (ns === 5) showNotif('\u26a1 5 votos! Vicia f\u00e1cil hein?');\n    else if (ns === 10) showNotif('\ud83d\udc51 10 votos! Rei das enquetes!');\n    await castVote(id, choice, user.uid, city || undefined, user.isAnonymous);\n    if (!user.isAnonymous) setVotaCoins(c => c + 1);\n    // Show WhatsApp modal after first vote if not subscribed\n    if (!hasVotedRef.current) {\n      hasVotedRef.current = true;\n      const sub = await getDoc(doc(db, 'subscribers', user.uid));\n      if (!sub.exists()) setTimeout(() => setShowWhatsApp(true), 1500);\n    }\n  }, [user, votes, streak, city]);\n\n  const handleCreate = async (data: any) => {\n    if (!user) return;\n    await createPoll({ ...data, userId: user.uid });\n    showNotif('\ud83c\udf89 Enquete publicada!');\n  };\n\n\n\n  const hotPoll = polls.find(p => p.hotOfDay);\n  const trending = [\n    ...(hotPoll ? [hotPoll] : []),\n    ...[...polls]\n      .filter(p => !p.hotOfDay)\n      .sort((a, b) => (b.totalVotes || 0) - (a.totalVotes || 0))\n  ];\n  const allTags = ['todos', ...Array.from(new Set(polls.map(p => p.tag).filter(Boolean)))].slice(0, 12);\n  const filteredPolls = polls.filter(p => {\n    const matchesTag = !activeTag || activeTag === 'todos' || p.tag === activeTag;\n    const matchesSearch = !search || p.question?.toLowerCase().includes(search.toLowerCase()) ||\n      p.optionA?.label?.toLowerCase().includes(search.toLowerCase()) ||\n      p.optionB?.label?.toLowerCase().includes(search.toLowerCase());\n    return matchesTag && matchesSearch;\n  });\n  const votedCount = Object.keys(votes).length;\n  const isAnon = user?.isAnonymous;\n\n  return (\n    <div className=\"min-h-screen\" style={{ background: '#07070E' }}>\n      {/* Notification */}\n      {notif && (\n        <div className=\"fixed top-4 left-1/2 -translate-x-1/2 z-50 px-5 py-3 rounded-2xl text-white font-bold text-sm shadow-2xl animate-fade-up\" style={{ background: '#6C63FF', minWidth: 200, textAlign: 'center' }}>\n          {notif}\n        </div>\n      )}\n\n      {/* Desktop layout */}\n      <div className=\"max-w-6xl mx-auto flex min-h-screen\" style={{ width: '100%' }}>\n\n        {/* Sidebar */}\n        <aside className=\"hidden md:flex flex-col w-64 p-6 sticky top-0 h-screen border-r\" style={{ borderColor: 'rgba(255,255,255,0.06)' }}>\n          <div className=\"mb-10\">\n            <a href=\"/\" className=\"text-4xl text-white\" style={{ fontFamily: 'var(--font-display)', letterSpacing: '0.05em', textDecoration: 'none' }}>VOTAAI</a>\n            <p className=\"text-xs mt-1\" style={{ color: 'rgba(255,255,255,0.3)' }}>Qual \u00e9 a sua?</p>\n          </div>\n\n          <nav className=\"space-y-1 flex-1\">\n            {[\n              { id: 'feed', icon: '\ud83c\udfe0', label: 'Feed' },\n              { id: 'trending', icon: '\ud83d\udcc8', label: 'Trending' },\n              { id: 'perfil', icon: '\ud83d\udc64', label: 'Perfil' },\n            ].map(item => (\n              <button\n                key={item.id}\n                onClick={() => setTab(item.id as any)}\n                className=\"w-full flex items-center gap-3 px-4 py-3 rounded-xl text-sm font-bold transition-all text-left\"\n                style={{\n                  background: tab === item.id ? 'rgba(108,99,255,0.15)' : 'transparent',\n                  color: tab === item.id ? '#6C63FF' : 'rgba(255,255,255,0.5)',\n                }}\n              >\n                <span className=\"text-lg\">{item.icon}</span> {item.label}\n              </button>\n            ))}\n          </nav>\n\n          <div className=\"space-y-3\">\n            {streak >= 3 && (\n              <div className=\"px-4 py-3 rounded-xl text-sm font-bold\" style={{ background: '#FF6B3520', color: '#FF6B35' }}>\n                \ud83d\udd25 Streak de {streak}!\n              </div>\n            )}\n            <button\n              onClick={() => setShowCreate(true)}\n              className=\"w-full py-3 rounded-xl font-black text-sm text-white transition-all hover:opacity-90 animate-pulse-glow\"\n              style={{ background: '#6C63FF', fontFamily: 'var(--font-display)', letterSpacing: '0.1em', fontSize: '1rem' }}\n            >\n              + CRIAR\n            </button>\n            {isAnon ? (\n              <button onClick={() => setShowAuth(true)} className=\"w-full py-3 rounded-xl text-sm font-bold border transition-all hover:bg-white/5\" style={{ borderColor: '#6C63FF66', color: '#6C63FF' }}>\n                \ud83d\udc64 Entrar / Cadastrar\n              </button>\n            ) : (\n              <div className=\"space-y-2\">\n                <button onClick={() => setTab('perfil')} className=\"w-full flex items-center justify-between px-3 py-2 rounded-xl transition-all hover:bg-white/5\" style={{ background: 'rgba(34,197,94,0.08)', border: '1px solid rgba(34,197,94,0.2)' }}>\n                  <div className=\"flex items-center gap-2\">\n                    <VotaCoin size={18} />\n                    <span className=\"text-sm font-black\" style={{ color: '#4ADE80' }}>{votaCoins} coins</span>\n                  </div>\n                  <span className=\"text-xs\" style={{ color: 'rgba(255,255,255,0.3)' }}>= R${(votaCoins * 0.01).toFixed(2)}</span>\n                </button>\n                <div className=\"px-3 py-2 rounded-xl text-xs\" style={{ background: 'rgba(255,255,255,0.04)', color: 'rgba(255,255,255,0.3)' }}>\n                  \ud83d\udc64 {user?.displayName || user?.email || 'An\u00f4nimo'}\n                </div>\n              </div>\n            )}\n          </div>\n        </aside>\n\n        {/* Fixed mobile header */}\n        <header className=\"fixed top-0 left-0 right-0 z-40 flex items-center justify-between px-4 py-3 md:hidden\" style={{ background: 'rgba(7,7,14,0.92)', backdropFilter: 'blur(12px)', borderBottom: '1px solid rgba(255,255,255,0.06)' }}>\n          <div>\n            <a href=\"/\" onClick={e => { e.preventDefault(); window.scrollTo({ top: 0, behavior: 'smooth' }); }} className=\"text-3xl text-white\" style={{ fontFamily: 'var(--font-display)', letterSpacing: '0.05em', textDecoration: 'none' }}>VOTAAI</a>\n            {votedCount > 0 && <p className=\"text-xs\" style={{ color: 'rgba(255,255,255,0.3)' }}>{votedCount} votos \u2022 \ud83d\udd25 {streak}</p>}\n          </div>\n          <div className=\"flex gap-2 items-center\">\n            {streak >= 3 && <span className=\"text-sm font-bold px-3 py-1 rounded-full\" style={{ background: '#FF6B3520', color: '#FF6B35' }}>\ud83d\udd25{streak}</span>}\n            {isAnon ? (\n              <button onClick={() => setShowAuth(true)} className=\"px-3 py-2 rounded-xl text-xs font-black border\" style={{ borderColor: '#6C63FF66', color: '#6C63FF' }}>Entrar</button>\n            ) : (\n              <div className=\"flex items-center gap-2\">\n                <button onClick={() => setTab('perfil')} className=\"flex items-center gap-1 px-2 py-1 rounded-full\" style={{ background: 'rgba(34,197,94,0.15)', border: '1px solid rgba(34,197,94,0.3)' }}>\n                    <VotaCoin size={16} />\n                    <span className=\"text-xs font-black\" style={{ color: '#4ADE80' }}>{votaCoins}</span>\n                  </button>\n                <div className=\"w-8 h-8 rounded-full flex items-center justify-center text-xs font-black\" style={{ background: '#6C63FF22', color: '#6C63FF', border: '1px solid #6C63FF44' }}>\n                  {(user?.displayName || user?.email || '?')[0].toUpperCase()}\n                </div>\n              </div>\n            )}\n            <button onClick={() => setShowCreate(true)} className=\"px-4 py-2 rounded-xl text-sm font-black text-white\" style={{ background: '#6C63FF' }}>+ Criar</button>\n          </div>\n        </header>\n\n        {/* Main content */}\n        <main className=\"flex-1 px-4 pt-20 pb-24 md:pt-6 md:pb-6\" style={{ minWidth: 0, width: '100%', maxWidth: 576, boxSizing: 'border-box', margin: '0 auto' }}>\n\n          {/* FEED */}\n          {tab === 'feed' && (\n            <div>\n              {/* Search */}\n              <div className=\"mb-3\">\n                <input\n                  className=\"w-full rounded-2xl px-4 py-3 text-sm text-white outline-none border transition-all\"\n                  style={{ background: 'rgba(255,255,255,0.05)', borderColor: search ? '#6C63FF' : 'rgba(255,255,255,0.08)' }}\n                  placeholder=\"\ud83d\udd0d Buscar enquetes...\"\n                  value={search}\n                  onChange={e => setSearch(e.target.value)}\n                />\n              </div>\n              {/* Category filters */}\n              <div className=\"mb-4\" style={{ display: 'flex', flexWrap: 'wrap', gap: 8, width: '100%' }}>\n                {allTags.map(tag => (\n                  <button\n                    key={tag}\n                    onClick={() => setActiveTag(tag === 'todos' ? null : tag)}\n                    className=\"px-3 py-1.5 rounded-full text-xs font-bold border transition-all capitalize\"\n                    style={{\n                      borderColor: (activeTag === tag || (tag === 'todos' && !activeTag)) ? '#6C63FF' : 'rgba(255,255,255,0.1)',\n                      background: (activeTag === tag || (tag === 'todos' && !activeTag)) ? 'rgba(108,99,255,0.2)' : 'transparent',\n                      color: (activeTag === tag || (tag === 'todos' && !activeTag)) ? '#6C63FF' : 'rgba(255,255,255,0.4)',\n                    }}\n                  >\n                    {tag}\n                  </button>\n                ))}\n              </div>\n              {loading ? (\n                <div className=\"space-y-4\">\n                  {[1,2,3].map(i => (\n                    <div key={i} className=\"rounded-2xl p-6 animate-pulse\" style={{ background: 'rgba(255,255,255,0.03)', height: 200 }} />\n                  ))}\n                </div>\n              ) : (\n                filteredPolls.map((poll, i) => (\n                  <div key={poll.id} ref={el => { pollRefs.current[poll.id] = el; }} style={{ animationDelay: `${i * 0.05}s`, transition: 'box-shadow 0.5s', borderRadius: 16, boxShadow: highlightedId === poll.id ? '0 0 0 3px #FF4E8C, 0 0 30px #FF4E8C44' : 'none' }} className=\"animate-fade-up\">\n                    <PollCard poll={poll} onVote={handleVote} userVote={votes[poll.id]} userId={user?.uid} isFirstVote={!isSubscribed && !!votes[poll.id]} onSubscribed={() => setIsSubscribed(true)} isAnon={isAnon} onShowAuth={() => setShowAuth(true)} />\n\n                    {showCity === poll.id && (\n                      <div className=\"rounded-2xl p-5 mb-4 border\" style={{ background: 'rgba(255,255,255,0.03)', borderColor: 'rgba(255,255,255,0.07)' }}>\n                        <p className=\"text-xs font-bold tracking-widest mb-4\" style={{ color: 'rgba(255,255,255,0.4)' }}>RESULTADO POR CIDADE</p>\n                        <CityMap poll={poll} color={poll.color} />\n                      </div>\n                    )}\n                  </div>\n                ))\n              )}\n              {!loading && filteredPolls.length === 0 && (\n                <div className=\"text-center py-20\" style={{ color: 'rgba(255,255,255,0.3)' }}>\n                  {search || activeTag ? '\ud83d\udd0d Nenhuma enquete encontrada' : 'Nenhuma enquete ainda. Crie a primeira! \ud83d\ude80'}\n                </div>\n              )}\n            </div>\n          )}\n\n          {/* TRENDING */}\n          {tab === 'trending' && (\n            <div>\n              <h2 className=\"text-3xl mb-1 text-white\" style={{ fontFamily: 'var(--font-display)', letterSpacing: '0.05em' }}>TRENDING</h2>\n              <p className=\"text-xs mb-6\" style={{ color: 'rgba(255,255,255,0.3)' }}>Enquetes mais votadas agora</p>\n              {trending.map((poll, i) => {\n                const total = poll.totalVotes || 0;\n                const pctA = total > 0 ? Math.round(((poll.votesA||0) / total) * 100) : 50;\n                const medals = ['\ud83e\udd47','\ud83e\udd48','\ud83e\udd49'];\n                const mColors = ['#F7B731','#AAAAAA','#CD7F32'];\n                const isHot = poll.hotOfDay && i === 0;\n                const pollUrl = poll.slug ? `/p/${poll.slug}` : null;\n                const CardWrapper = ({ children }: { children: React.ReactNode }) => pollUrl ? (\n                  <a href={pollUrl} className=\"flex gap-4 p-5 rounded-2xl mb-3 border block transition-all hover:opacity-80\" style={{ background: isHot ? 'rgba(255,78,140,0.07)' : 'rgba(255,255,255,0.03)', borderColor: isHot ? '#FF4E8C44' : poll.color + '22', textDecoration: 'none' }}>\n                    {children}\n                  </a>\n                ) : (\n                  <div className=\"flex gap-4 p-5 rounded-2xl mb-3 border\" style={{ background: 'rgba(255,255,255,0.03)', borderColor: poll.color + '22' }}>\n                    {children}\n                  </div>\n                );\n                return (\n                  <CardWrapper key={poll.id}>\n                    <div className=\"flex gap-4 flex-1 min-w-0\">\n                      <span className=\"text-2xl font-black shrink-0\" style={{ color: isHot ? '#FF4E8C' : i < 3 ? mColors[i] : 'rgba(255,255,255,0.2)', fontFamily: 'var(--font-display)' }}>\n                        {isHot ? '\ud83d\udd25' : i < 3 ? medals[i] : `#${i+1}`}\n                      </span>\n                      <div className=\"flex-1 min-w-0\">\n                        {isHot && <span className=\"text-xs font-black tracking-widest px-2 py-0.5 rounded-full mb-1 inline-block\" style={{ background: '#FF4E8C22', color: '#FF4E8C' }}>POL\u00caMICA DO DIA</span>}\n                        <p className=\"text-sm font-bold text-white truncate\">{poll.question}</p>\n                        <p className=\"text-xs mt-0.5 truncate\" style={{ color: 'rgba(255,255,255,0.4)' }}>{poll.optionA?.emoji} {poll.optionA?.label} <span style={{ color: 'rgba(255,255,255,0.2)' }}>vs</span> {poll.optionB?.emoji} {poll.optionB?.label}</p>\n                        <div className=\"flex items-center gap-2 mt-2\">\n                          <div className=\"flex-1 h-1.5 rounded-full overflow-hidden\" style={{ background: 'rgba(255,255,255,0.07)' }}>\n                            <div className=\"h-full rounded-full\" style={{ width: `${pctA}%`, background: isHot ? '#FF4E8C' : poll.color }} />\n                          </div>\n                          <span className=\"text-xs font-bold shrink-0\" style={{ color: isHot ? '#FF4E8C' : poll.color }}>{pctA}%</span>\n                        </div>\n                        <p className=\"text-xs mt-1\" style={{ color: 'rgba(255,255,255,0.3)' }}>{fmt(total)} votos</p>\n                      </div>\n                    </div>\n                  </CardWrapper>\n                );\n              })}\n            </div>\n          )}\n\n          {/* PERFIL */}\n          {tab === 'perfil' && (\n            <div>\n              <div className=\"flex items-center justify-between mb-6\">\n                <button onClick={() => setTab('feed')} className=\"text-2xl font-black text-white\" style={{ fontFamily: 'var(--font-display)', letterSpacing: '0.05em', background: 'none', border: 'none', cursor: 'pointer' }}>\u2190 VOTAAI</button>\n              </div>\n              <div className=\"rounded-2xl p-6 mb-4 text-center border\" style={{ background: 'rgba(255,255,255,0.03)', borderColor: '#6C63FF33' }}>\n                <div className=\"w-16 h-16 rounded-full mx-auto mb-3 flex items-center justify-center text-3xl border-2\" style={{ background: '#6C63FF22', borderColor: '#6C63FF' }}>\n                  {isAnon ? '\ud83d\uddf3\ufe0f' : '\ud83d\ude0e'}\n                </div>\n                <p className=\"font-black text-white text-lg\">{user?.displayName || (isAnon ? 'Votante An\u00f4nimo' : user?.email)}</p>\n                <p className=\"text-xs mt-1\" style={{ color: 'rgba(255,255,255,0.3)' }}>{city ? `\ud83d\udccd ${city}` : 'Localiza\u00e7\u00e3o desconhecida'}</p>\n                {isAnon && (\n                  <button onClick={() => setShowAuth(true)} className=\"mt-4 px-5 py-2 rounded-xl text-sm font-bold border\" style={{ borderColor: '#6C63FF66', color: '#6C63FF' }}>\n                    \ud83d\udce7 Criar conta\n                  </button>\n                )}\n              </div>\n\n              <div className=\"grid grid-cols-2 gap-3 mb-6\">\n                {[\n                  { label: 'Votos dados', value: votedCount, emoji: '\ud83d\uddf3\ufe0f', color: '#6C63FF' },\n                  { label: 'Streak atual', value: `${streak}\ud83d\udd25`, emoji: '\u26a1', color: '#FF6B35' },\n                  { label: 'Enquetes', value: polls.length, emoji: '\ud83d\udccb', color: '#00C9A7' },\n                  { label: 'Cidade', value: city || '?', emoji: '\ud83d\udccd', color: '#FF4E8C' },\n                ].map(stat => (\n                  <div key={stat.label} className=\"p-4 rounded-2xl text-center border\" style={{ background: 'rgba(255,255,255,0.03)', borderColor: stat.color + '33' }}>\n                    <div className=\"text-2xl mb-2\">{stat.emoji}</div>\n                    <div className=\"text-xl font-black\" style={{ color: stat.color, fontFamily: 'var(--font-display)' }}>{stat.value}</div>\n                    <div className=\"text-xs mt-1\" style={{ color: 'rgba(255,255,255,0.3)' }}>{stat.label}</div>\n                  </div>\n                ))}\n              </div>\n\n              {/* VotaCoins card */}\n              {!isAnon && (\n                <div className=\"rounded-2xl p-5 mb-4 border\" style={{ background: 'rgba(34,197,94,0.05)', borderColor: 'rgba(34,197,94,0.2)' }}>\n                  <div className=\"flex items-center justify-between mb-3\">\n                    <div>\n                      <div className=\"flex items-center gap-2 mb-1\">\n                        <VotaCoin size={22} />\n                        <p className=\"text-xs font-bold tracking-widest\" style={{ color: '#4ADE80' }}>VOTACOINS</p>\n                      </div>\n                      <p className=\"text-3xl font-black text-white mt-1\" style={{ fontFamily: 'var(--font-display)' }}>{votaCoins} <span className=\"text-base\" style={{ color: 'rgba(255,255,255,0.4)' }}>= R${(votaCoins * 0.01).toFixed(2)}</span></p>\n                    </div>\n                    <div className=\"text-right\">\n                      <p className=\"text-xs\" style={{ color: 'rgba(255,255,255,0.3)' }}>Saque m\u00edn.</p>\n                      <p className=\"text-sm font-black\" style={{ color: '#F7B731' }}>R$20,00</p>\n                    </div>\n                  </div>\n                  <div className=\"mb-3\">\n                    <div className=\"flex justify-between text-xs mb-1\" style={{ color: 'rgba(255,255,255,0.3)' }}>\n                      <span>{votaCoins} coins</span>\n                      <span>2.000 coins</span>\n                    </div>\n                    <div className=\"h-2 rounded-full overflow-hidden\" style={{ background: 'rgba(255,255,255,0.07)' }}>\n                      <div className=\"h-full rounded-full transition-all\" style={{ width: `${Math.min((votaCoins / 2000) * 100, 100)}%`, background: 'linear-gradient(90deg, #F7B731, #FF6B35)' }} />\n                    </div>\n                  </div>\n                  {votaCoins >= 2000 ? (\n                    <SaqueForm coins={votaCoins} email={user?.email || ''} uid={user?.uid || ''} onSaque={() => {}} />\n                  ) : (\n                    <p className=\"text-xs text-center\" style={{ color: 'rgba(255,255,255,0.3)' }}>\n                      Faltam {Math.max(0, 2000 - votaCoins)} coins para sacar \u00b7 Vote mais enquetes!\n                    </p>\n                  )}\n                </div>\n              )}\n\n              <button\n                onClick={() => { signOut(auth); setTab('feed'); }}\n                className=\"w-full py-3 rounded-xl text-sm font-bold border mb-6 transition-all hover:bg-white/5\"\n                style={{ borderColor: 'rgba(255,82,82,0.3)', color: '#FF5252' }}\n              >\n                \ud83d\udeaa Sair da conta\n              </button>\n\n              {votedCount > 0 && (\n                <>\n                  <p className=\"text-xs font-bold tracking-widest mb-3\" style={{ color: 'rgba(255,255,255,0.4)' }}>HIST\u00d3RICO DE VOTOS</p>\n                  {Object.entries(votes).map(([id, choice]) => {\n                    const poll = polls.find(p => p.id === id);\n                    if (!poll) return null;\n                    const chosen = choice === 'A' ? poll.optionA : poll.optionB;\n                    return (\n                      <div key={id} className=\"flex items-center gap-3 p-4 rounded-xl mb-2 border\" style={{ background: 'rgba(255,255,255,0.03)', borderColor: 'rgba(255,255,255,0.06)' }}>\n                        <span className=\"text-2xl\">{chosen?.emoji}</span>\n                        <div className=\"flex-1 min-w-0\">\n                          <p className=\"text-sm font-bold text-white truncate\">{chosen?.label}</p>\n                          <p className=\"text-xs truncate\" style={{ color: 'rgba(255,255,255,0.3)' }}>{poll.question}</p>\n                        </div>\n                        <span className=\"text-xs font-black px-2 py-1 rounded-lg border\" style={{ color: poll.color, borderColor: poll.color + '44', background: poll.color + '11' }}>{choice}</span>\n                      </div>\n                    );\n                  })}\n                </>\n              )}\n            </div>\n          )}\n        </main>\n      </div>\n\n      {/* Mobile tab bar */}\n      <div className=\"fixed bottom-0 left-0 right-0 md:hidden flex items-center px-4 pb-safe border-t\" style={{ background: 'rgba(7,7,14,0.97)', backdropFilter: 'blur(20px)', borderColor: 'rgba(255,255,255,0.07)', paddingBottom: 'max(16px, env(safe-area-inset-bottom))' }}>\n        {[\n          { id: 'feed', icon: '\ud83c\udfe0', label: 'Feed' },\n          { id: 'trending', icon: '\ud83d\udcc8', label: 'Trends' },\n          { id: 'perfil', icon: '\ud83d\udc64', label: 'Perfil' },\n        ].map(item => (\n          <button key={item.id} onClick={() => setTab(item.id as any)} className=\"flex-1 flex flex-col items-center py-3 gap-1\">\n            <span className=\"text-xl\">{item.icon}</span>\n            <span className=\"text-xs font-bold\" style={{ color: tab === item.id ? '#6C63FF' : 'rgba(255,255,255,0.3)' }}>{item.label}</span>\n          </button>\n        ))}\n        <button onClick={() => setShowCreate(true)} className=\"px-4 py-2 rounded-xl text-sm font-black text-white ml-2\" style={{ background: '#6C63FF' }}>+ Criar</button>\n      </div>\n\n      {showAuth && (\n        <AuthModal onClose={() => setShowAuth(false)} anonUid={isAnon ? user?.uid : undefined} />\n      )}\n      {showCreate && <CreatePollModal onClose={() => setShowCreate(false)} onCreate={handleCreate} />}\n    </div>\n  );\n}\n\nexport default function Home() { return <HomeCore />; }\n");
fs.writeFileSync("src/app/admin/page.tsx", "'use client';\nimport { useState, useEffect } from 'react';\nimport { collection, getDocs, doc, deleteDoc, setDoc, serverTimestamp, getDoc, updateDoc, query, orderBy, onSnapshot } from 'firebase/firestore';\nimport { db, auth } from '@/lib/firebase';\nimport { onAuthStateChanged, User, signInWithEmailAndPassword } from 'firebase/auth';\n\n\nconst ADMIN_EMAIL = 'vinicius.pessin@gmail.com';\nconst DEFAULT_TAGS = ['comida','vida','esporte','estilo de vida','rotina','superpoderes','trabalho','tecnologia','entretenimento','outro'];\n\nfunction fmt(n: number) {\n  if (n >= 1000) return (n / 1000).toFixed(1) + 'k';\n  return String(n || 0);\n}\n\n\nfunction parseSlug(slug: string) {\n  return slug\n    .replace(/-[a-z0-9]{5}$/, '')\n    .replace(/-/g, ' ')\n    .replace(/\b\\w/g, (c: string) => c.toUpperCase());\n}\n\nasync function callClaude(prompt: string) {\n  const res = await fetch('https://api.anthropic.com/v1/messages', {\n    method: 'POST',\n    headers: { 'Content-Type': 'application/json' },\n    body: JSON.stringify({\n      model: 'claude-sonnet-4-20250514',\n      max_tokens: 1000,\n      system: 'Voc\u00ea \u00e9 um assistente criativo para redes sociais brasileiras. Responda sempre em JSON puro, sem markdown.',\n      messages: [{ role: 'user', content: prompt }],\n    }),\n  });\n  const data = await res.json();\n  return data.content?.[0]?.text || '';\n}\n\nconst CARD_FORMATS = [\n  { id: 'stories', label: 'Stories 9:16', w: 1080, h: 1920, scale: 0.17 },\n  { id: 'feed', label: 'Feed 1:1', w: 1080, h: 1080, scale: 0.24 },\n  { id: 'twitter', label: 'Twitter 16:9', w: 1200, h: 675, scale: 0.30 },\n  { id: 'whatsapp', label: 'WhatsApp', w: 800, h: 800, scale: 0.28 },\n];\n\nfunction PollCardPreview({ fmt, question, optA, optB, pctA, url }: any) {\n  const pctB = 100 - pctA;\n  const W = fmt.w * fmt.scale;\n  const H = fmt.h * fmt.scale;\n  const isStory = fmt.id === 'stories';\n  const qFont = isStory ? 22 : fmt.id === 'twitter' ? 18 : 20;\n  const oFont = isStory ? 14 : 12;\n\n  return (\n    <div style={{ width: W, height: H, position: 'relative', overflow: 'hidden', borderRadius: 10, flexShrink: 0,\n      background: 'linear-gradient(135deg, #0d0d1a, #1a0a2e 40%, #0a1628)',\n      boxShadow: '0 16px 48px rgba(0,0,0,0.6)' }}>\n      <div style={{ position: 'absolute', inset: 0,\n        background: 'radial-gradient(ellipse at 20% 20%, rgba(108,99,255,0.25) 0%, transparent 50%), radial-gradient(ellipse at 80% 80%, rgba(255,78,140,0.2) 0%, transparent 50%)' }} />\n      <div style={{ position: 'absolute', inset: 0, display: 'flex', flexDirection: 'column',\n        justifyContent: 'space-between', padding: isStory ? `${H*0.07}px ${W*0.07}px` : `${H*0.08}px ${W*0.06}px` }}>\n        {/* Logo */}\n        <div style={{ fontSize: isStory ? 12 : 9, fontWeight: 900, letterSpacing: 3, color: 'rgba(255,255,255,0.4)', fontFamily: 'monospace' }}>\n          VOTAAI \ud83d\udd25\n        </div>\n        {/* Question */}\n        <div style={{ fontSize: qFont, fontWeight: 700, color: 'white', lineHeight: 1.3,\n          borderLeft: '3px solid #FF4E8C', paddingLeft: 12 }}>\n          {question || 'Sua enquete aqui'}\n        </div>\n        {/* Bars */}\n        <div style={{ display: 'flex', flexDirection: 'column', gap: isStory ? 10 : 7 }}>\n          {[{ label: optA, pct: pctA, color: '#6C63FF', e: '\u2705' }, { label: optB, pct: pctB, color: '#FF4E8C', e: '\u274c' }].map((o, i) => (\n            <div key={i}>\n              <div style={{ display: 'flex', justifyContent: 'space-between', marginBottom: 4 }}>\n                <span style={{ fontSize: oFont, color: 'rgba(255,255,255,0.85)', fontWeight: 600 }}>{o.e} {o.label}</span>\n                <span style={{ fontSize: oFont, color: o.color, fontWeight: 900 }}>{o.pct}%</span>\n              </div>\n              <div style={{ height: isStory ? 7 : 5, borderRadius: 99, background: 'rgba(255,255,255,0.08)', overflow: 'hidden' }}>\n                <div style={{ height: '100%', width: `${o.pct}%`, borderRadius: 99, background: o.color }} />\n              </div>\n            </div>\n          ))}\n        </div>\n        {/* CTA */}\n        <div style={{ background: 'linear-gradient(90deg, #6C63FF, #FF4E8C)', borderRadius: isStory ? 14 : 10,\n          padding: isStory ? '12px 16px' : '8px 12px', textAlign: 'center' }}>\n          <div style={{ fontSize: isStory ? 13 : 10, fontWeight: 900, color: 'white' }}>\ud83d\uddf3\ufe0f Vote voc\u00ea tamb\u00e9m</div>\n          <div style={{ fontSize: isStory ? 11 : 9, color: 'rgba(255,255,255,0.7)', fontFamily: 'monospace', marginTop: 2 }}>\n            {url || 'votaai.app'}\n          </div>\n        </div>\n      </div>\n    </div>\n  );\n}\n\nfunction CardGenerator({ polls }: { polls: any[] }) {\n  const [selectedPoll, setSelectedPoll] = useState<any>(null);\n  const [question, setQuestion] = useState('');\n  const [optA, setOptA] = useState('Sim');\n  const [optB, setOptB] = useState('N\u00e3o');\n  const [pctA, setPctA] = useState(55);\n  const [caption, setCaption] = useState('');\n  const [isGenerating, setIsGenerating] = useState(false);\n  const [activeFormat, setActiveFormat] = useState('stories');\n  const [copied, setCopied] = useState(false);\n\n  const handleSelectPoll = async (poll: any) => {\n    setSelectedPoll(poll);\n    setQuestion(poll.question || '');\n    setOptA(poll.optionA?.label || 'Sim');\n    setOptB(poll.optionB?.label || 'N\u00e3o');\n    const total = (poll.votesA || 0) + (poll.votesB || 0);\n    const pct = total > 0 ? Math.round(((poll.votesA || 0) / total) * 100) : 55;\n    setPctA(pct);\n    setCaption('');\n    setIsGenerating(true);\n    try {\n      const url = `https://votaai.app/p/${poll.slug}`;\n      const raw = await callClaude(\n        `Enquete brasileira: \"${poll.question}\"\\nOp\u00e7\u00e3o A: \"${poll.optionA?.label}\" (${pct}%)\\nOp\u00e7\u00e3o B: \"${poll.optionB?.label}\" (${100-pct}%)\\nURL: ${url}\\n\\nGere um JSON com:\\n{\\n  \"caption\": \"legenda viral para Instagram com emojis e hashtags brasileiras relevantes. M\u00e1x 220 chars. Termine com CTA para votar.\"\\n}`\n      );\n      const json = JSON.parse(raw.replace(/\\`\\`\\`json|\\`\\`\\`/g, '').trim());\n      setCaption(json.caption || '');\n    } catch (e) {\n      setCaption(`\ud83d\udd25 ${poll.question}\\n\\nVote e ganhe VotaCoins! \ud83d\udc49 votaai.app/p/${poll.slug}\\n\\n#votaai #enquete #poll`);\n    }\n    setIsGenerating(false);\n  };\n\n  const fmt = CARD_FORMATS.find(f => f.id === activeFormat)!;\n  const pollUrl = selectedPoll?.slug ? `votaai.app/p/${selectedPoll.slug}` : 'votaai.app';\n\n  return (\n    <div>\n      {/* Poll selector */}\n      <p className=\"text-xs font-bold tracking-widest mb-3\" style={{ color: 'rgba(255,255,255,0.4)' }}>\n        SELECIONE A ENQUETE\n      </p>\n      <div className=\"grid grid-cols-1 gap-2 mb-6\" style={{ maxHeight: 220, overflowY: 'auto' }}>\n        {polls.map(p => (\n          <button key={p.id} onClick={() => handleSelectPoll(p)}\n            className=\"text-left px-4 py-3 rounded-xl text-sm transition-all\"\n            style={{\n              background: selectedPoll?.id === p.id ? 'rgba(108,99,255,0.15)' : 'rgba(255,255,255,0.03)',\n              border: `1px solid ${selectedPoll?.id === p.id ? 'rgba(108,99,255,0.5)' : 'rgba(255,255,255,0.06)'}`,\n              color: selectedPoll?.id === p.id ? 'white' : 'rgba(255,255,255,0.5)',\n            }}>\n            {p.hotOfDay && <span className=\"text-xs font-black mr-2\" style={{ color: '#FF4E8C' }}>\ud83d\udd25</span>}\n            {p.question}\n          </button>\n        ))}\n      </div>\n\n      {selectedPoll && (\n        <>\n          {/* Format tabs */}\n          <div className=\"flex gap-2 mb-5 flex-wrap\">\n            {CARD_FORMATS.map(f => (\n              <button key={f.id} onClick={() => setActiveFormat(f.id)}\n                className=\"px-4 py-2 rounded-xl text-xs font-bold transition-all\"\n                style={{ background: activeFormat === f.id ? '#FF4E8C' : 'rgba(255,255,255,0.05)', color: activeFormat === f.id ? 'white' : 'rgba(255,255,255,0.4)' }}>\n                {f.label}\n              </button>\n            ))}\n          </div>\n\n          {/* Preview */}\n          <div className=\"flex justify-center items-center rounded-2xl mb-5 p-8\"\n            style={{ background: 'rgba(255,255,255,0.02)', border: '1px solid rgba(255,255,255,0.06)', minHeight: 300 }}>\n            {isGenerating ? (\n              <div className=\"text-center\" style={{ color: 'rgba(255,255,255,0.3)' }}>\n                <div className=\"text-3xl mb-2\">\u23f3</div>\n                <p className=\"text-sm\">Gerando legenda com IA...</p>\n              </div>\n            ) : (\n              <PollCardPreview fmt={fmt} question={question} optA={optA} optB={optB} pctA={pctA} url={pollUrl} />\n            )}\n          </div>\n\n          {/* Adjustments */}\n          <div className=\"rounded-2xl p-5 mb-5 border\" style={{ background: 'rgba(255,255,255,0.02)', borderColor: 'rgba(255,255,255,0.06)' }}>\n            <p className=\"text-xs font-bold tracking-widest mb-4\" style={{ color: 'rgba(255,255,255,0.4)' }}>AJUSTAR</p>\n            <div className=\"space-y-3\">\n              <textarea value={question} onChange={e => setQuestion(e.target.value)} rows={2}\n                className=\"w-full rounded-xl px-4 py-3 text-sm text-white outline-none border resize-none\"\n                style={{ background: 'rgba(255,255,255,0.04)', borderColor: 'rgba(255,255,255,0.1)' }} />\n              <div className=\"flex gap-3\">\n                <input value={optA} onChange={e => setOptA(e.target.value)} placeholder=\"Op\u00e7\u00e3o A\"\n                  className=\"flex-1 rounded-xl px-3 py-2 text-sm text-white outline-none border\"\n                  style={{ background: 'rgba(255,255,255,0.04)', borderColor: 'rgba(108,99,255,0.3)' }} />\n                <input value={optB} onChange={e => setOptB(e.target.value)} placeholder=\"Op\u00e7\u00e3o B\"\n                  className=\"flex-1 rounded-xl px-3 py-2 text-sm text-white outline-none border\"\n                  style={{ background: 'rgba(255,255,255,0.04)', borderColor: 'rgba(255,78,140,0.3)' }} />\n              </div>\n              <div className=\"flex items-center gap-3\">\n                <span className=\"text-xs w-16\" style={{ color: 'rgba(255,255,255,0.4)' }}>A: {pctA}%</span>\n                <input type=\"range\" min={20} max={80} value={pctA} onChange={e => setPctA(+e.target.value)} className=\"flex-1\" style={{ accentColor: '#6C63FF' }} />\n                <span className=\"text-xs w-16 text-right\" style={{ color: 'rgba(255,255,255,0.4)' }}>B: {100-pctA}%</span>\n              </div>\n            </div>\n          </div>\n\n          {/* Caption */}\n          {caption && (\n            <div className=\"rounded-2xl p-5 border\" style={{ background: 'rgba(255,255,255,0.02)', borderColor: 'rgba(255,255,255,0.06)' }}>\n              <div className=\"flex justify-between items-center mb-3\">\n                <p className=\"text-xs font-bold tracking-widest\" style={{ color: 'rgba(255,255,255,0.4)' }}>LEGENDA GERADA POR IA</p>\n                <button onClick={() => { navigator.clipboard.writeText(caption + '\\n\\n\ud83d\udc49 ' + pollUrl); setCopied(true); setTimeout(() => setCopied(false), 2000); }}\n                  className=\"px-4 py-1.5 rounded-xl text-xs font-bold transition-all\"\n                  style={{ background: copied ? 'rgba(34,197,94,0.2)' : 'rgba(255,255,255,0.07)', color: copied ? '#4ADE80' : 'rgba(255,255,255,0.5)' }}>\n                  {copied ? '\u2705 Copiado!' : '\ud83d\udccb Copiar legenda'}\n                </button>\n              </div>\n              <textarea value={caption} onChange={e => setCaption(e.target.value)} rows={4}\n                className=\"w-full rounded-xl px-4 py-3 text-sm outline-none border resize-none\"\n                style={{ background: 'rgba(255,255,255,0.04)', borderColor: 'rgba(255,255,255,0.08)', color: 'rgba(255,255,255,0.7)', lineHeight: 1.6 }} />\n              <p className=\"text-xs mt-2 font-black\" style={{ color: '#6C63FF' }}>\ud83d\udc49 {pollUrl}</p>\n            </div>\n          )}\n        </>\n      )}\n    </div>\n  );\n}\n\nfunction AdminLogin() {\n  const [email, setEmail] = useState('');\n  const [password, setPassword] = useState('');\n  const [error, setError] = useState('');\n  const [loading, setLoading] = useState(false);\n\n  const handleLogin = async () => {\n    setError('');\n    setLoading(true);\n    try {\n      await signInWithEmailAndPassword(auth, email, password);\n    } catch (e: any) {\n      setError('Email ou senha incorretos.');\n    }\n    setLoading(false);\n  };\n\n  return (\n    <div className=\"space-y-3\">\n      <input\n        className=\"w-full rounded-xl px-4 py-3 text-sm text-white outline-none border\"\n        style={{ background: 'rgba(255,255,255,0.05)', borderColor: 'rgba(108,99,255,0.3)' }}\n        placeholder=\"Email\"\n        type=\"email\"\n        value={email}\n        onChange={e => setEmail(e.target.value)}\n        onKeyDown={e => e.key === 'Enter' && handleLogin()}\n      />\n      <input\n        className=\"w-full rounded-xl px-4 py-3 text-sm text-white outline-none border\"\n        style={{ background: 'rgba(255,255,255,0.05)', borderColor: 'rgba(108,99,255,0.3)' }}\n        placeholder=\"Senha\"\n        type=\"password\"\n        value={password}\n        onChange={e => setPassword(e.target.value)}\n        onKeyDown={e => e.key === 'Enter' && handleLogin()}\n      />\n      {error && <p className=\"text-xs text-center\" style={{ color: '#FF5252' }}>{error}</p>}\n      <button\n        onClick={handleLogin}\n        disabled={loading || !email || !password}\n        className=\"w-full py-3 rounded-xl text-sm font-black text-white transition-all\"\n        style={{ background: email && password ? '#6C63FF' : 'rgba(255,255,255,0.07)' }}\n      >\n        {loading ? '\u23f3 Entrando...' : '\ud83d\udd10 Entrar'}\n      </button>\n    </div>\n  );\n}\n\nexport default function AdminPage() {\n  const [user, setUser] = useState<User | null>(null);\n  const [polls, setPolls] = useState<any[]>([]);\n  const [loading, setLoading] = useState(true);\n  const [deleting, setDeleting] = useState<string | null>(null);\n  const [search, setSearch] = useState('');\n  const [sortBy, setSortBy] = useState<'order' | 'popular'>('order');\n  const [toast, setToast] = useState<string | null>(null);\n  const [activeTab, setActiveTab] = useState<'polls' | 'categories' | 'whatsapp' | 'members' | 'pagamentos' | 'cards'>('polls');\n  const [saques, setSaques] = useState<any[]>([]);\n  const [categories, setCategories] = useState<string[]>(DEFAULT_TAGS);\n  const [newCat, setNewCat] = useState('');\n  const [savingCat, setSavingCat] = useState(false);\n  const [subscribers, setSubscribers] = useState<any[]>([]);\n  const [members, setMembers] = useState<any[]>([]);\n\n  useEffect(() => {\n    const unsub = onAuthStateChanged(auth, u => { setUser(u); setLoading(false); });\n    return unsub;\n  }, []);\n\n  useEffect(() => {\n    if (user?.email === ADMIN_EMAIL) {\n      fetchPolls();\n      fetchCategories();\n      fetchSubscribers();\n      fetchMembers();\n      // Real-time saques listener\n      const q = query(collection(db, 'saques'), orderBy('requestedAt', 'desc'));\n      const unsub = onSnapshot(q, snap => setSaques(snap.docs.map(d => ({ id: d.id, ...d.data() }))));\n      return unsub;\n    }\n  }, [user]);\n\n  const fetchPolls = async () => {\n    const q = query(collection(db, 'polls'), orderBy('createdAt', 'desc'));\n    const snap = await getDocs(q);\n    const data = snap.docs.map((d, i) => ({ id: d.id, ...d.data(), _order: (d.data() as any).order ?? i }));\n    setPolls(data.sort((a, b) => a._order - b._order));\n  };\n\n  const fetchCategories = async () => {\n    try {\n      const snap = await getDoc(doc(db, 'config', 'categories'));\n      if (snap.exists()) setCategories(snap.data().list || DEFAULT_TAGS);\n    } catch { setCategories(DEFAULT_TAGS); }\n  };\n\n  const fetchSubscribers = async () => {\n    const snap = await getDocs(collection(db, 'subscribers'));\n    setSubscribers(snap.docs.map(d => ({ id: d.id, ...d.data() })).filter((s: any) => s.active));\n  };\n\n  const fetchMembers = async () => {\n    const snap = await getDocs(collection(db, 'members'));\n    const list = snap.docs.map(d => ({ id: d.id, ...d.data() }));\n    setMembers(list.sort((a: any, b: any) => new Date(b.joinedAt || 0).getTime() - new Date(a.joinedAt || 0).getTime()));\n  };\n\n  const showToast = (msg: string) => { setToast(msg); setTimeout(() => setToast(null), 3000); };\n\n  const handleDelete = async (id: string, question: string) => {\n    if (!confirm(`Deletar enquete?\\n\\n\"${question}\"\\n\\nEsta a\u00e7\u00e3o n\u00e3o pode ser desfeita.`)) return;\n    setDeleting(id);\n    await deleteDoc(doc(db, 'polls', id));\n    setPolls(p => p.filter(x => x.id !== id));\n    setDeleting(null);\n    showToast('\ud83d\uddd1\ufe0f Enquete deletada!');\n  };\n\n  const handlePin = async (id: string, pinned: boolean) => {\n    await updateDoc(doc(db, 'polls', id), { pinned: !pinned });\n    setPolls(p => p.map(x => x.id === id ? { ...x, pinned: !pinned } : x));\n    showToast(pinned ? '\ud83d\udccc Enquete desafixada' : '\ud83d\udccc Enquete fixada no topo!');\n  };\n\n  const handleHotOfDay = async (id: string, current: boolean) => {\n    if (!current) {\n      const toRemove = polls.filter(p => p.hotOfDay && p.id !== id);\n      await Promise.all(toRemove.map(p => updateDoc(doc(db, 'polls', p.id), { hotOfDay: false })));\n    }\n    await updateDoc(doc(db, 'polls', id), { hotOfDay: !current });\n    setPolls(p => p.map(x => ({ ...x, hotOfDay: x.id === id ? !current : (!current ? false : x.hotOfDay) })));\n    showToast(!current ? '\ud83d\udd25 Pol\u00eamica do Dia definida!' : '\ud83d\udd25 Selo removido');\n  };\n\n  const handleMove = async (index: number, direction: 'up' | 'down') => {\n    const newPolls = [...polls];\n    const swapIndex = direction === 'up' ? index - 1 : index + 1;\n    if (swapIndex < 0 || swapIndex >= newPolls.length) return;\n    [newPolls[index], newPolls[swapIndex]] = [newPolls[swapIndex], newPolls[index]];\n    setPolls(newPolls);\n    await Promise.all([\n      updateDoc(doc(db, 'polls', newPolls[index].id), { order: index }),\n      updateDoc(doc(db, 'polls', newPolls[swapIndex].id), { order: swapIndex }),\n    ]);\n    showToast('\u2195\ufe0f Ordem atualizada!');\n  };\n\n  const handleAddCategory = async () => {\n    const cat = newCat.trim().toLowerCase();\n    if (!cat || categories.includes(cat)) return;\n    setSavingCat(true);\n    const updated = [...categories, cat];\n    await setDoc(doc(db, 'config', 'categories'), { list: updated });\n    setCategories(updated);\n    setNewCat('');\n    setSavingCat(false);\n    showToast(`\u2705 Categoria \"${cat}\" criada!`);\n  };\n\n  const handleDeleteCategory = async (cat: string) => {\n    if (DEFAULT_TAGS.includes(cat)) return showToast('\u26a0\ufe0f N\u00e3o \u00e9 poss\u00edvel deletar categorias padr\u00e3o');\n    const updated = categories.filter(c => c !== cat);\n    await setDoc(doc(db, 'config', 'categories'), { list: updated });\n    setCategories(updated);\n    showToast(`\ud83d\uddd1\ufe0f Categoria \"${cat}\" removida`);\n  };\n\n  const exportMembersCSV = () => {\n    const csv = [\n      'Email,Data de cadastro,Votos,Provedor',\n      ...members.map((m: any) => `${m.email},${m.joinedAt ? new Date(m.joinedAt).toLocaleDateString('pt-BR') : '-'},${m.voteCount},${m.provider === 'google.com' ? 'Google' : 'Email'}`)\n    ].join('\\n');\n    const blob = new Blob([csv], { type: 'text/csv' });\n    const url = URL.createObjectURL(blob);\n    const a = document.createElement('a');\n    a.href = url; a.download = 'membros-votaai.csv'; a.click();\n    URL.revokeObjectURL(url);\n  };\n\n  if (loading) return (\n    <div className=\"min-h-screen flex items-center justify-center\" style={{ background: '#07070E' }}>\n      <div className=\"text-white/40 text-sm\">Carregando...</div>\n    </div>\n  );\n\n  const isAdmin = user?.email === ADMIN_EMAIL;\n  const filtered = polls\n    .filter(p => p.question?.toLowerCase().includes(search.toLowerCase()) ||\n      p.optionA?.label?.toLowerCase().includes(search.toLowerCase()) ||\n      p.optionB?.label?.toLowerCase().includes(search.toLowerCase()))\n    .sort((a, b) => sortBy === 'popular' ? (b.totalVotes || 0) - (a.totalVotes || 0) : (a._order - b._order));\n  const totalVotes = polls.reduce((acc, p) => acc + (p.totalVotes || 0), 0);\n  const hotPoll = polls.find(p => p.hotOfDay);\n\n  return (\n    <div className=\"min-h-screen\" style={{ background: '#07070E' }}>\n      {toast && (\n        <div className=\"fixed top-4 left-1/2 -translate-x-1/2 z-50 px-5 py-3 rounded-2xl text-white font-bold text-sm shadow-2xl\" style={{ background: '#6C63FF' }}>\n          {toast}\n        </div>\n      )}\n\n      <div className=\"border-b px-6 py-4 flex items-center justify-between\" style={{ borderColor: 'rgba(255,255,255,0.07)', background: 'rgba(255,255,255,0.02)' }}>\n        <div className=\"flex items-center gap-3\">\n          <a href=\"/\" className=\"text-sm font-bold\" style={{ color: 'rgba(255,255,255,0.4)' }}>\u2190 VotaA\u00ed</a>\n          <span style={{ color: 'rgba(255,255,255,0.15)' }}>/</span>\n          <h1 className=\"text-lg font-black text-white\" style={{ fontFamily: 'var(--font-display)', letterSpacing: '0.05em' }}>ADMIN</h1>\n        </div>\n        {isAdmin && <span className=\"text-xs px-3 py-1 rounded-full\" style={{ background: 'rgba(0,201,167,0.15)', color: '#00C9A7' }}>\u2705 {user?.email}</span>}\n      </div>\n\n      {!isAdmin ? (\n        <div className=\"min-h-screen flex items-center justify-center p-4\">\n          <div className=\"w-full max-w-sm\">\n            <div className=\"text-center mb-8\">\n              <div className=\"text-5xl mb-4\">\ud83d\udd12</div>\n              <h1 className=\"text-3xl font-black text-white mb-1\" style={{ fontFamily: 'var(--font-display)', letterSpacing: '0.05em' }}>VOTAAI</h1>\n              <p className=\"text-sm\" style={{ color: 'rgba(255,255,255,0.4)' }}>Painel administrativo</p>\n            </div>\n            <AdminLogin />\n            <a href=\"/\" className=\"block mt-6 text-sm text-center\" style={{ color: 'rgba(255,255,255,0.3)' }}>\u2190 Voltar ao site</a>\n          </div>\n        </div>\n      ) : (\n        <div className=\"max-w-4xl mx-auto p-6\">\n\n          {/* Stats */}\n          <div className=\"grid grid-cols-5 gap-4 mb-6\">\n            {[\n              { label: 'Enquetes', value: polls.length, emoji: '\ud83d\udccb', color: '#6C63FF' },\n              { label: 'Votos totais', value: fmt(totalVotes), emoji: '\ud83d\uddf3\ufe0f', color: '#00C9A7' },\n              { label: 'Membros', value: members.length, emoji: '\ud83d\udc65', color: '#FF4E8C' },\n              { label: 'Inscritos ZAP', value: subscribers.length, emoji: '\ud83d\udcac', color: '#25D366' },\n              { label: 'Saques pend.', value: saques.filter(s => s.status === 'pendente').length, emoji: '\ud83d\udcb8', color: '#F7B731' },\n            ].map(s => (\n              <div key={s.label} className=\"rounded-2xl p-4 border text-center\" style={{ background: 'rgba(255,255,255,0.03)', borderColor: s.color + '33' }}>\n                <div className=\"text-xl mb-1\">{s.emoji}</div>\n                <div className=\"text-xl font-black\" style={{ color: s.color, fontFamily: 'var(--font-display)' }}>{s.value}</div>\n                <div className=\"text-xs mt-0.5\" style={{ color: 'rgba(255,255,255,0.3)' }}>{s.label}</div>\n              </div>\n            ))}\n          </div>\n\n          {/* Tabs */}\n          <div className=\"flex gap-2 mb-6 flex-wrap\">\n            {[\n              { id: 'polls', label: '\ud83d\udccb Enquetes' },\n              { id: 'members', label: '\ud83d\udc65 Membros' },\n              { id: 'whatsapp', label: '\ud83d\udcac WhatsApp' },\n              { id: 'categories', label: '\ud83c\udff7\ufe0f Categorias' },\n              { id: 'pagamentos', label: '\ud83d\udcb8 Pagamentos' },\n              { id: 'cards', label: '\ud83c\udfa8 Cards' },\n            ].map(t => (\n              <button key={t.id} onClick={() => setActiveTab(t.id as any)} className=\"px-5 py-2.5 rounded-xl text-sm font-bold transition-all\" style={{ background: activeTab === t.id ? '#6C63FF' : 'rgba(255,255,255,0.05)', color: activeTab === t.id ? 'white' : 'rgba(255,255,255,0.4)' }}>\n                {t.label}\n              </button>\n            ))}\n          </div>\n\n          {/* POLLS TAB */}\n          {activeTab === 'polls' && (\n            <>\n              <div className=\"flex gap-3 mb-6\">\n                <input className=\"flex-1 rounded-xl px-4 py-3 text-sm text-white outline-none border\" style={{ background: 'rgba(255,255,255,0.05)', borderColor: 'rgba(255,255,255,0.1)' }} placeholder=\"\ud83d\udd0d Buscar enquetes...\" value={search} onChange={e => setSearch(e.target.value)} />\n                <button onClick={() => setSortBy(s => s === 'order' ? 'popular' : 'order')} className=\"px-4 py-3 rounded-xl text-sm font-bold border\" style={{ borderColor: 'rgba(255,255,255,0.1)', color: 'rgba(255,255,255,0.5)', background: 'rgba(255,255,255,0.03)' }}>\n                  {sortBy === 'order' ? '\u2195\ufe0f Ordem' : '\ud83d\udcc8 Populares'}\n                </button>\n                <button onClick={fetchPolls} className=\"px-4 py-3 rounded-xl text-sm font-bold border\" style={{ borderColor: 'rgba(255,255,255,0.1)', color: 'rgba(255,255,255,0.5)', background: 'rgba(255,255,255,0.03)' }}>\ud83d\udd04</button>\n              </div>\n              <div className=\"space-y-3\">\n                {filtered.map((poll) => {\n                  const total = poll.totalVotes || 0;\n                  const pctA = total > 0 ? Math.round(((poll.votesA || 0) / total) * 100) : 50;\n                  const realIndex = polls.findIndex(p => p.id === poll.id);\n                  return (\n                    <div key={poll.id} className=\"rounded-2xl p-5 border transition-all\" style={{ background: poll.pinned ? 'rgba(247,183,49,0.05)' : 'rgba(255,255,255,0.03)', borderColor: poll.hotOfDay ? '#FF4E8C33' : poll.pinned ? '#F7B73133' : 'rgba(255,255,255,0.07)' }}>\n                      <div className=\"flex items-start gap-4\">\n                        {sortBy === 'order' && (\n                          <div className=\"flex flex-col gap-1 shrink-0 mt-1\">\n                            <button onClick={() => handleMove(realIndex, 'up')} disabled={realIndex === 0} className=\"w-7 h-7 rounded-lg flex items-center justify-center text-xs\" style={{ background: 'rgba(255,255,255,0.06)', color: realIndex === 0 ? 'rgba(255,255,255,0.15)' : 'rgba(255,255,255,0.6)' }}>\u25b2</button>\n                            <div className=\"text-center text-xs font-bold\" style={{ color: 'rgba(255,255,255,0.2)' }}>{realIndex + 1}</div>\n                            <button onClick={() => handleMove(realIndex, 'down')} disabled={realIndex === polls.length - 1} className=\"w-7 h-7 rounded-lg flex items-center justify-center text-xs\" style={{ background: 'rgba(255,255,255,0.06)', color: realIndex === polls.length - 1 ? 'rgba(255,255,255,0.15)' : 'rgba(255,255,255,0.6)' }}>\u25bc</button>\n                          </div>\n                        )}\n                        <div className=\"w-3 h-3 rounded-full mt-1.5 shrink-0\" style={{ background: poll.color || '#6C63FF' }} />\n                        <div className=\"flex-1 min-w-0\">\n                          <div className=\"flex items-center gap-2 mb-1 flex-wrap\">\n                            {poll.hotOfDay && <span className=\"text-xs px-2 py-0.5 rounded-full font-bold\" style={{ background: '#FF4E8C22', color: '#FF4E8C' }}>\ud83d\udd25 Pol\u00eamica do Dia</span>}\n                            {poll.pinned && <span className=\"text-xs px-2 py-0.5 rounded-full font-bold\" style={{ background: '#F7B73122', color: '#F7B731' }}>\ud83d\udccc Fixada</span>}\n                            <span className=\"text-xs font-bold tracking-widest uppercase\" style={{ color: 'rgba(255,255,255,0.3)' }}>{poll.tag}</span>\n                          </div>\n                          <p className=\"text-white font-bold text-sm mb-2\">{poll.question}</p>\n                          <div className=\"flex items-center gap-3 text-xs mb-3\" style={{ color: 'rgba(255,255,255,0.4)' }}>\n                            <span>{poll.optionA?.emoji} {poll.optionA?.label}</span>\n                            <span style={{ color: 'rgba(255,255,255,0.2)' }}>vs</span>\n                            <span>{poll.optionB?.emoji} {poll.optionB?.label}</span>\n                          </div>\n                          <div className=\"flex items-center gap-2\">\n                            <span className=\"text-xs font-bold\" style={{ color: poll.color || '#6C63FF', minWidth: 32 }}>{pctA}%</span>\n                            <div className=\"flex-1 h-1.5 rounded-full overflow-hidden\" style={{ background: 'rgba(255,255,255,0.07)' }}>\n                              <div className=\"h-full rounded-full\" style={{ width: `${pctA}%`, background: poll.color || '#6C63FF' }} />\n                            </div>\n                            <span className=\"text-xs font-bold\" style={{ color: 'rgba(255,255,255,0.3)', minWidth: 32, textAlign: 'right' }}>{100 - pctA}%</span>\n                            <span className=\"text-xs ml-2\" style={{ color: 'rgba(255,255,255,0.25)' }}>{fmt(total)} votos</span>\n                          </div>\n                        </div>\n                        <div className=\"flex flex-col gap-2 shrink-0\">\n                          <button onClick={() => handleHotOfDay(poll.id, !!poll.hotOfDay)} className=\"px-3 py-1.5 rounded-lg text-xs font-bold border transition-all\" style={{ borderColor: poll.hotOfDay ? '#FF4E8C44' : 'rgba(255,255,255,0.1)', color: poll.hotOfDay ? '#FF4E8C' : 'rgba(255,255,255,0.4)', background: poll.hotOfDay ? '#FF4E8C11' : 'transparent' }}>\n                            {poll.hotOfDay ? '\ud83d\udd25 Ativa' : '\ud83d\udd25 Setar'}\n                          </button>\n                          <button onClick={() => handlePin(poll.id, poll.pinned)} className=\"px-3 py-1.5 rounded-lg text-xs font-bold border transition-all\" style={{ borderColor: poll.pinned ? '#F7B73144' : 'rgba(255,255,255,0.1)', color: poll.pinned ? '#F7B731' : 'rgba(255,255,255,0.4)', background: poll.pinned ? '#F7B73111' : 'transparent' }}>\n                            {poll.pinned ? '\ud83d\udccc Fixada' : '\ud83d\udccc Fixar'}\n                          </button>\n                          <button onClick={() => handleDelete(poll.id, poll.question)} disabled={deleting === poll.id} className=\"px-3 py-1.5 rounded-lg text-xs font-bold border\" style={{ borderColor: '#FF525233', color: '#FF5252', background: 'rgba(255,82,82,0.07)' }}>\n                            {deleting === poll.id ? '...' : '\ud83d\uddd1\ufe0f Deletar'}\n                          </button>\n                        </div>\n                      </div>\n                    </div>\n                  );\n                })}\n                {filtered.length === 0 && <div className=\"text-center py-16\" style={{ color: 'rgba(255,255,255,0.3)' }}>Nenhuma enquete encontrada</div>}\n              </div>\n            </>\n          )}\n\n          {/* MEMBERS TAB */}\n          {activeTab === 'members' && (\n            <div>\n              <div className=\"flex items-center justify-between mb-6\">\n                <div>\n                  <p className=\"text-white font-black text-lg\">{members.length} membros</p>\n                  <p className=\"text-xs mt-1\" style={{ color: 'rgba(255,255,255,0.4)' }}>Usu\u00e1rios com conta cadastrada</p>\n                </div>\n                <div className=\"flex gap-2\">\n                  <button onClick={fetchMembers} className=\"px-4 py-2 rounded-xl text-sm font-bold border\" style={{ borderColor: 'rgba(255,255,255,0.1)', color: 'rgba(255,255,255,0.5)', background: 'rgba(255,255,255,0.03)' }}>\ud83d\udd04</button>\n                  <button onClick={exportMembersCSV} className=\"px-4 py-2 rounded-xl text-sm font-bold border\" style={{ borderColor: '#00C9A733', color: '#00C9A7', background: 'rgba(0,201,167,0.07)' }}>\n                    \ud83d\udce5 Exportar CSV\n                  </button>\n                </div>\n              </div>\n              <div className=\"space-y-2\">\n                {members.map((m: any) => (\n                  <div key={m.id} className=\"flex items-center gap-4 p-4 rounded-xl border\" style={{ background: 'rgba(255,255,255,0.03)', borderColor: 'rgba(255,255,255,0.07)' }}>\n                    <div className=\"w-9 h-9 rounded-full flex items-center justify-center font-black text-sm shrink-0\" style={{ background: m.provider === 'google.com' ? '#4285F422' : '#6C63FF22', color: m.provider === 'google.com' ? '#4285F4' : '#6C63FF' }}>\n                      {(m.email || '?')[0].toUpperCase()}\n                    </div>\n                    <div className=\"flex-1 min-w-0\">\n                      <p className=\"text-sm font-bold text-white truncate\">{m.email}</p>\n                      <p className=\"text-xs mt-0.5\" style={{ color: 'rgba(255,255,255,0.3)' }}>\n                        {m.provider === 'google.com' ? '\ud83d\udd35 Google' : '\ud83d\udce7 Email'} \u00b7 {m.joinedAt ? new Date(m.joinedAt).toLocaleDateString('pt-BR') : '-'}\n                      </p>\n                    </div>\n                    <div className=\"text-right shrink-0\">\n                      <p className=\"text-sm font-black\" style={{ color: '#6C63FF' }}>{m.voteCount}</p>\n                      <p className=\"text-xs\" style={{ color: 'rgba(255,255,255,0.3)' }}>votos</p>\n                    </div>\n                  </div>\n                ))}\n                {members.length === 0 && <p className=\"text-center py-16 text-sm\" style={{ color: 'rgba(255,255,255,0.3)' }}>Nenhum membro ainda</p>}\n              </div>\n            </div>\n          )}\n\n          {/* WHATSAPP TAB */}\n          {activeTab === 'whatsapp' && (\n            <div>\n              <div className=\"flex items-center justify-between mb-6\">\n                <div>\n                  <p className=\"text-white font-black text-lg\">{subscribers.length} inscritos</p>\n                  <p className=\"text-xs mt-1\" style={{ color: 'rgba(255,255,255,0.4)' }}>Recebem a Pol\u00eamica do Dia no WhatsApp</p>\n                </div>\n                <button onClick={fetchSubscribers} className=\"px-4 py-2 rounded-xl text-sm font-bold border\" style={{ borderColor: 'rgba(255,255,255,0.1)', color: 'rgba(255,255,255,0.5)', background: 'rgba(255,255,255,0.03)' }}>\ud83d\udd04</button>\n              </div>\n              {!hotPoll ? (\n                <div className=\"p-4 rounded-xl mb-6 text-sm text-center\" style={{ background: 'rgba(255,82,82,0.1)', color: '#FF5252', border: '1px solid #FF525233' }}>\n                  \u26a0\ufe0f Defina uma Pol\u00eamica do Dia antes de disparar\n                </div>\n              ) : (\n                <div className=\"p-4 rounded-xl mb-6 border\" style={{ background: 'rgba(247,183,49,0.05)', borderColor: '#F7B73133' }}>\n                  <p className=\"text-xs font-bold tracking-widest mb-2\" style={{ color: '#F7B731' }}>\ud83d\udd25 POL\u00caMICA DO DIA ATIVA</p>\n                  <p className=\"text-white font-bold text-sm mb-1\">{hotPoll.question}</p>\n                  <p className=\"text-xs mb-4\" style={{ color: 'rgba(255,255,255,0.4)' }}>Clique em cada contato para abrir o WhatsApp e enviar.</p>\n                  <div className=\"space-y-2 max-h-96 overflow-y-auto\">\n                    {subscribers.map((s: any) => {\n                      const msg = encodeURIComponent(`\ud83d\udd25 POL\u00caMICA DO DIA no VotaA\u00ed!\\n${hotPoll.question}\\nhttps://votaai.app\\nResponda SAIR para cancelar`);\n                      return (\n                        <a key={s.id} href={`https://wa.me/55${s.phone}?text=${msg}`} target=\"_blank\" rel=\"noopener noreferrer\" className=\"flex items-center justify-between p-3 rounded-xl border transition-all\" style={{ background: 'rgba(37,211,102,0.05)', borderColor: '#25D36633' }}>\n                          <div>\n                            <p className=\"text-sm font-bold text-white\">{s.name || 'An\u00f4nimo'}</p>\n                            <p className=\"text-xs\" style={{ color: 'rgba(255,255,255,0.3)' }}>+55 {s.phone}</p>\n                          </div>\n                          <span className=\"text-lg\">\ud83d\udcac</span>\n                        </a>\n                      );\n                    })}\n                    {subscribers.length === 0 && <p className=\"text-center text-sm py-4\" style={{ color: 'rgba(255,255,255,0.3)' }}>Nenhum inscrito ainda</p>}\n                  </div>\n                </div>\n              )}\n            </div>\n          )}\n\n          {/* CATEGORIES TAB */}\n          {activeTab === 'pagamentos' && (\n            <div className=\"space-y-4\">\n              <div className=\"flex items-center justify-between mb-2\">\n                <p className=\"text-sm\" style={{ color: 'rgba(255,255,255,0.4)' }}>\n                  {saques.filter(s => s.status === 'pendente').length} pendentes \u00b7 {saques.filter(s => s.status === 'pago').length} pagos\n                </p>\n              </div>\n              {saques.length === 0 && (\n                <div className=\"text-center py-12\" style={{ color: 'rgba(255,255,255,0.2)' }}>Nenhuma solicita\u00e7\u00e3o ainda</div>\n              )}\n              {saques.map(s => (\n                <div key={s.id} className=\"rounded-2xl p-5 border\" style={{ background: 'rgba(255,255,255,0.03)', borderColor: s.status === 'pago' ? 'rgba(34,197,94,0.2)' : s.status === 'pendente' ? 'rgba(247,183,49,0.3)' : 'rgba(255,82,82,0.2)' }}>\n                  <div className=\"flex items-start justify-between gap-4\">\n                    <div className=\"flex-1 min-w-0\">\n                      <div className=\"flex items-center gap-2 mb-1\">\n                        <span className=\"text-xs font-black px-2 py-0.5 rounded-full\" style={{\n                          background: s.status === 'pago' ? 'rgba(34,197,94,0.15)' : s.status === 'pendente' ? 'rgba(247,183,49,0.15)' : 'rgba(255,82,82,0.15)',\n                          color: s.status === 'pago' ? '#4ADE80' : s.status === 'pendente' ? '#F7B731' : '#FF5252',\n                        }}>\n                          {s.status === 'pago' ? '\u2705 PAGO' : s.status === 'pendente' ? '\u23f3 PENDENTE' : '\u274c RECUSADO'}\n                        </span>\n                        <span className=\"text-xs\" style={{ color: 'rgba(255,255,255,0.3)' }}>\n                          {s.requestedAt?.toDate?.().toLocaleDateString('pt-BR', { day: '2-digit', month: '2-digit', year: 'numeric', hour: '2-digit', minute: '2-digit' }) || '\u2014'}\n                        </span>\n                      </div>\n                      <p className=\"text-white font-bold\">{s.email}</p>\n                      <div className=\"flex items-center gap-4 mt-2\">\n                        <span className=\"text-lg font-black\" style={{ color: '#F7B731' }}>R${s.valor?.toFixed(2)}</span>\n                        <span className=\"text-xs\" style={{ color: 'rgba(255,255,255,0.4)' }}>{s.coins} coins</span>\n                      </div>\n                      <div className=\"mt-2 px-3 py-2 rounded-xl inline-flex items-center gap-2\" style={{ background: 'rgba(255,255,255,0.05)' }}>\n                        <span className=\"text-xs font-bold uppercase\" style={{ color: 'rgba(255,255,255,0.3)' }}>{s.pixType}</span>\n                        <span className=\"text-sm font-black text-white\">{s.pixKey}</span>\n                        <button onClick={() => navigator.clipboard.writeText(s.pixKey)} className=\"text-xs px-2 py-0.5 rounded-lg transition-all hover:bg-white/10\" style={{ color: '#6C63FF' }}>copiar</button>\n                      </div>\n                    </div>\n                    {s.status === 'pendente' && (\n                      <div className=\"flex flex-col gap-2 shrink-0\">\n                        <button\n                          onClick={async () => { await updateDoc(doc(db, 'saques', s.id), { status: 'pago', paidAt: serverTimestamp() }); }}\n                          className=\"px-4 py-2 rounded-xl text-xs font-black transition-all\"\n                          style={{ background: 'rgba(34,197,94,0.2)', color: '#4ADE80', border: '1px solid rgba(34,197,94,0.3)' }}\n                        >\u2705 Marcar pago</button>\n                        <button\n                          onClick={async () => { await updateDoc(doc(db, 'saques', s.id), { status: 'recusado' }); }}\n                          className=\"px-4 py-2 rounded-xl text-xs font-black transition-all\"\n                          style={{ background: 'rgba(255,82,82,0.1)', color: '#FF5252', border: '1px solid rgba(255,82,82,0.2)' }}\n                        >\u274c Recusar</button>\n                      </div>\n                    )}\n                  </div>\n                </div>\n              ))}\n            </div>\n          )}\n\n          {activeTab === 'categories' && (\n            <div>\n              <p className=\"text-sm mb-6\" style={{ color: 'rgba(255,255,255,0.4)' }}>Categorias aparecem no modal de cria\u00e7\u00e3o de enquetes. As categorias padr\u00e3o n\u00e3o podem ser removidas.</p>\n              <div className=\"flex gap-3 mb-6\">\n                <input className=\"flex-1 rounded-xl px-4 py-3 text-sm text-white outline-none border\" style={{ background: 'rgba(255,255,255,0.05)', borderColor: 'rgba(255,255,255,0.1)' }} placeholder=\"Nova categoria...\" value={newCat} onChange={e => setNewCat(e.target.value)} onKeyDown={e => e.key === 'Enter' && handleAddCategory()} />\n                <button onClick={handleAddCategory} disabled={!newCat.trim() || savingCat} className=\"px-5 py-3 rounded-xl text-sm font-black transition-all\" style={{ background: newCat.trim() ? '#6C63FF' : 'rgba(255,255,255,0.07)', color: newCat.trim() ? 'white' : 'rgba(255,255,255,0.3)' }}>\n                  {savingCat ? '...' : '+ Adicionar'}\n                </button>\n              </div>\n              <div className=\"grid grid-cols-2 gap-3\">\n                {categories.map(cat => {\n                  const isDefault = DEFAULT_TAGS.includes(cat);\n                  const pollCount = polls.filter(p => p.tag === cat).length;\n                  return (\n                    <div key={cat} className=\"flex items-center justify-between p-4 rounded-xl border\" style={{ background: 'rgba(255,255,255,0.03)', borderColor: 'rgba(255,255,255,0.07)' }}>\n                      <div>\n                        <p className=\"text-sm font-bold text-white capitalize\">{cat}</p>\n                        <p className=\"text-xs mt-0.5\" style={{ color: 'rgba(255,255,255,0.3)' }}>{pollCount} enquete{pollCount !== 1 ? 's' : ''}</p>\n                      </div>\n                      <div className=\"flex items-center gap-2\">\n                        {isDefault && <span className=\"text-xs px-2 py-0.5 rounded-full\" style={{ background: 'rgba(255,255,255,0.07)', color: 'rgba(255,255,255,0.3)' }}>padr\u00e3o</span>}\n                        {!isDefault && <button onClick={() => handleDeleteCategory(cat)} className=\"w-7 h-7 rounded-lg flex items-center justify-center text-xs\" style={{ background: 'rgba(255,82,82,0.1)', color: '#FF5252' }}>\u2715</button>}\n                      </div>\n                    </div>\n                  );\n                })}\n              </div>\n            </div>\n          )}\n          {activeTab === 'cards' && (\n            <CardGenerator polls={polls} />\n          )}\n\n        </div>\n      )}\n    </div>\n  );\n}\n");
fs.writeFileSync("src/components/AuthModal.tsx", "'use client';\nimport { useState } from 'react';\nimport {\n  signInWithEmailAndPassword,\n  linkWithCredential, EmailAuthProvider, User,\n} from 'firebase/auth';\nimport { auth, db } from '@/lib/firebase';\nimport { doc, getDocs, collection, setDoc, deleteDoc } from 'firebase/firestore';\n\ntype Mode = 'choose' | 'login' | 'register';\n\nconst formatPhone = (v: string) => {\n  const digits = v.replace(/\\D/g, '').slice(0, 11);\n  if (digits.length <= 2) return digits;\n  if (digits.length <= 7) return `(${digits.slice(0,2)}) ${digits.slice(2)}`;\n  return `(${digits.slice(0,2)}) ${digits.slice(2,7)}-${digits.slice(7)}`;\n};\n\nconst WELCOME_BONUS = 50;\nconst SAQUE_MINIMO = 2000;\n\nconst saveMemberProfile = async (u: User | null, phone?: string, isNew?: boolean) => {\n  if (!u || u.isAnonymous || !u.email) return;\n  const ref = doc(db, 'members', u.uid);\n\n  if (isNew) {\n    // Create document fresh with welcome bonus as plain number\n    const data: any = {\n      email: u.email,\n      displayName: u.displayName || null,\n      provider: u.providerData?.[0]?.providerId || 'password',\n      joinedAt: u.metadata?.creationTime || null,\n      lastLogin: new Date().toISOString(),\n      uid: u.uid,\n      votaCoins: WELCOME_BONUS,\n      voteCount: 0,\n      welcomeBonusGranted: true,\n    };\n    if (phone) data.phone = phone.replace(/\\D/g, '');\n    await setDoc(ref, data).catch(e => console.error('members write error:', e));\n  } else {\n    // Existing user \u2014 just update login fields, never touch votaCoins\n    const data: any = {\n      email: u.email,\n      displayName: u.displayName || null,\n      provider: u.providerData?.[0]?.providerId || 'password',\n      lastLogin: new Date().toISOString(),\n      uid: u.uid,\n    };\n    if (phone) data.phone = phone.replace(/\\D/g, '');\n    await setDoc(ref, data, { merge: true }).catch(e => console.error('members write error:', e));\n  }\n\n  // Also save to subscribers if phone provided\n  if (phone) {\n    const cleanPhone = phone.replace(/\\D/g, '');\n    await setDoc(doc(db, 'subscribers', u.uid), {\n      phone: cleanPhone,\n      name: u.displayName || u.email,\n      userId: u.uid,\n      active: true,\n      joinedAt: new Date().toISOString(),\n    }, { merge: true }).catch(() => null);\n  }\n};\n\nconst migrateVotes = async (fromUid: string, toUid: string) => {\n  try {\n    const snap = await getDocs(collection(db, `users/${fromUid}/votes`));\n    await Promise.all(snap.docs.map(d =>\n      setDoc(doc(db, `users/${toUid}/votes/${d.id}`), d.data())\n    ));\n    const subSnap = await getDocs(collection(db, 'subscribers'));\n    const sub = subSnap.docs.find(d => d.id === fromUid);\n    if (sub) {\n      await setDoc(doc(db, 'subscribers', toUid), { ...sub.data(), userId: toUid });\n      await deleteDoc(doc(db, 'subscribers', fromUid));\n    }\n  } catch (e) {\n    console.error('migrate error', e);\n  }\n};\n\nexport default function AuthModal({ onClose, anonUid }: {\n  onClose: () => void;\n  anonUid?: string;\n}) {\n  const [mode, setMode] = useState<Mode>('choose');\n  const [email, setEmail] = useState('');\n  const [password, setPassword] = useState('');\n  const [phone, setPhone] = useState('');\n  const [loading, setLoading] = useState(false);\n  const [error, setError] = useState('');\n\n  const handleEmailAuth = async () => {\n    if (!email || password.length < 6) {\n      setError('Email v\u00e1lido e senha com m\u00ednimo 6 caracteres.');\n      return;\n    }\n    setLoading(true);\n    setError('');\n    try {\n      const currentUser = auth.currentUser;\n      const credential = EmailAuthProvider.credential(email, password);\n      let isNew = false;\n\n      if (mode === 'register') {\n        if (currentUser?.isAnonymous) {\n          try {\n            await linkWithCredential(currentUser, credential);\n            isNew = true;\n          } catch (linkErr: any) {\n            if (linkErr.code === 'auth/email-already-in-use') {\n              setError('Este email j\u00e1 est\u00e1 cadastrado. Tente fazer login.');\n              setLoading(false);\n              return;\n            }\n            throw linkErr;\n          }\n        } else {\n          const { createUserWithEmailAndPassword } = await import('firebase/auth');\n          await createUserWithEmailAndPassword(auth, email, password);\n          isNew = true;\n        }\n      } else {\n        const prevUid = currentUser?.isAnonymous ? anonUid : undefined;\n        const result = await signInWithEmailAndPassword(auth, email, password);\n        if (prevUid && prevUid !== result.user.uid) await migrateVotes(prevUid, result.user.uid);\n      }\n      await saveMemberProfile(auth.currentUser, phone || undefined, isNew);\n      onClose();\n    } catch (e: any) {\n      if (e.code === 'auth/user-not-found' || e.code === 'auth/wrong-password' || e.code === 'auth/invalid-credential') {\n        setError('Email ou senha incorretos.');\n      } else if (e.code === 'auth/email-already-in-use') {\n        setError('Email j\u00e1 cadastrado. Fa\u00e7a login.');\n      } else if (e.code === 'auth/invalid-email') {\n        setError('Email inv\u00e1lido.');\n      } else {\n        setError('Erro inesperado. Tente novamente.');\n      }\n    }\n    setLoading(false);\n  };\n\n  return (\n    <div className=\"fixed inset-0 z-50 flex items-end sm:items-center justify-center p-4\">\n      <div className=\"absolute inset-0 bg-black/70 backdrop-blur-sm\" onClick={onClose} />\n      <div className=\"relative w-full max-w-sm rounded-2xl p-6 border\" style={{ background: '#13131A', borderColor: 'rgba(255,255,255,0.1)' }}>\n\n        <div className=\"flex items-center justify-between mb-6\">\n          <div>\n            {mode !== 'choose' && (\n              <button onClick={() => { setMode('choose'); setError(''); }} className=\"text-xs mb-1 flex items-center gap-1\" style={{ color: 'rgba(255,255,255,0.4)' }}>\n                \u2190 Voltar\n              </button>\n            )}\n            <h2 className=\"text-xl font-black text-white\" style={{ fontFamily: 'var(--font-display)', letterSpacing: '0.05em' }}>\n              {mode === 'choose' ? 'ENTRAR' : mode === 'login' ? 'LOGIN' : 'CADASTRO'}\n            </h2>\n            <p className=\"text-xs mt-0.5\" style={{ color: 'rgba(255,255,255,0.4)' }}>\n              {mode === 'register'\n                ? `\ud83e\ude99 Ganhe ${WELCOME_BONUS} VotaCoins de boas-vindas!`\n                : mode === 'login' ? 'Entre na sua conta'\n                : 'Vote e ganhe VotaCoins'}\n            </p>\n          </div>\n          <button onClick={onClose} className=\"w-7 h-7 rounded-full flex items-center justify-center text-xs\" style={{ background: 'rgba(255,255,255,0.07)', color: 'rgba(255,255,255,0.4)' }}>\u2715</button>\n        </div>\n\n        {mode === 'choose' && (\n          <div className=\"space-y-3\">\n            {/* VotaCoins bonus banner */}\n            <div className=\"p-4 rounded-2xl text-center\" style={{ background: 'linear-gradient(135deg, rgba(247,183,49,0.12), rgba(255,107,53,0.08))', border: '1px solid rgba(247,183,49,0.3)' }}>\n              <div className=\"text-2xl mb-1\">\ud83c\udf81</div>\n              <p className=\"text-sm font-black text-white\">Ganhe <span style={{ color: '#F7B731' }}>{WELCOME_BONUS} VotaCoins</span> de b\u00f4nus!</p>\n              <p className=\"text-xs mt-1\" style={{ color: 'rgba(255,255,255,0.5)' }}>S\u00f3 por criar sua conta agora \u00b7 Vale R${(WELCOME_BONUS * 0.01).toFixed(2)}</p>\n              <div className=\"mt-2 pt-2\" style={{ borderTop: '1px solid rgba(255,255,255,0.08)' }}>\n                <p className=\"text-xs\" style={{ color: 'rgba(255,255,255,0.35)' }}>+ 1 VotaCoin por voto \u00b7 Saque m\u00edn. R${SAQUE_MINIMO / 100}</p>\n              </div>\n            </div>\n            <button onClick={() => setMode('register')} className=\"w-full py-3.5 rounded-xl font-bold text-sm transition-all\" style={{ background: 'linear-gradient(90deg, #6C63FF, #FF6B35)', color: 'white' }}>\n              \ud83c\udf81 Criar conta e ganhar b\u00f4nus\n            </button>\n            <button onClick={() => setMode('login')} className=\"w-full py-3.5 rounded-xl font-bold text-sm border transition-all hover:bg-white/5\" style={{ borderColor: 'rgba(255,255,255,0.1)', color: 'rgba(255,255,255,0.6)' }}>\n              J\u00e1 tenho conta \u2014 entrar\n            </button>\n            <button onClick={onClose} className=\"w-full py-2 text-xs\" style={{ color: 'rgba(255,255,255,0.25)' }}>\n              Continuar sem conta\n            </button>\n          </div>\n        )}\n\n        {(mode === 'login' || mode === 'register') && (\n          <div className=\"space-y-3\">\n            <input\n              className=\"w-full rounded-xl px-4 py-3 text-sm text-white outline-none border\"\n              style={{ background: 'rgba(255,255,255,0.05)', borderColor: error ? '#FF525244' : 'rgba(255,255,255,0.1)' }}\n              placeholder=\"Email\"\n              type=\"email\"\n              value={email}\n              onChange={e => { setEmail(e.target.value); setError(''); }}\n              inputMode=\"email\"\n              autoCapitalize=\"none\"\n            />\n            <input\n              className=\"w-full rounded-xl px-4 py-3 text-sm text-white outline-none border\"\n              style={{ background: 'rgba(255,255,255,0.05)', borderColor: error ? '#FF525244' : 'rgba(255,255,255,0.1)' }}\n              placeholder=\"Senha (m\u00ednimo 6 caracteres)\"\n              type=\"password\"\n              value={password}\n              onChange={e => { setPassword(e.target.value); setError(''); }}\n            />\n            {mode === 'register' && (\n              <div className=\"relative\">\n                <input\n                  className=\"w-full rounded-xl px-4 py-3 text-sm text-white outline-none border\"\n                  style={{ background: 'rgba(255,255,255,0.05)', borderColor: 'rgba(255,255,255,0.1)' }}\n                  placeholder=\"(11) 99999-9999\"\n                  type=\"tel\"\n                  value={phone}\n                  onChange={e => setPhone(formatPhone(e.target.value))}\n                  inputMode=\"tel\"\n                />\n                <span className=\"absolute right-3 top-1/2 -translate-y-1/2 text-xs\" style={{ color: 'rgba(255,255,255,0.25)' }}>opcional</span>\n              </div>\n            )}\n            {error && <p className=\"text-xs px-1\" style={{ color: '#FF5252' }}>{error}</p>}\n            {mode === 'register' && (\n              <div className=\"px-1 py-2 rounded-xl text-xs text-center\" style={{ background: 'rgba(247,183,49,0.08)', color: '#F7B731' }}>\n                \ud83e\ude99 +{WELCOME_BONUS} VotaCoins de boas-vindas ao cadastrar!\n              </div>\n            )}\n            <button\n              onClick={handleEmailAuth}\n              disabled={loading || !email || password.length < 6}\n              className=\"w-full py-3.5 rounded-xl font-black text-sm transition-all\"\n              style={{\n                background: email && password.length >= 6 ? '#6C63FF' : 'rgba(255,255,255,0.07)',\n                color: email && password.length >= 6 ? 'white' : 'rgba(255,255,255,0.3)',\n                fontFamily: 'var(--font-display)',\n                letterSpacing: '0.1em',\n              }}\n            >\n              {loading ? 'AGUARDE...' : mode === 'login' ? 'ENTRAR' : 'CADASTRAR'}\n            </button>\n            <button onClick={() => setMode(mode === 'login' ? 'register' : 'login')} className=\"w-full py-2 text-xs text-center\" style={{ color: 'rgba(255,255,255,0.35)' }}>\n              {mode === 'login' ? 'N\u00e3o tem conta? Cadastre-se' : 'J\u00e1 tem conta? Entre'}\n            </button>\n          </div>\n        )}\n      </div>\n    </div>\n  );\n}\n");
fs.writeFileSync("src/lib/polls.ts", "import {\n  collection, doc, getDocs, addDoc, updateDoc,\n  increment, onSnapshot, orderBy, query, where,\n  serverTimestamp, setDoc, getDoc,\n} from 'firebase/firestore';\nimport { signInAnonymously, GoogleAuthProvider, signInWithPopup, signInWithRedirect, getRedirectResult } from 'firebase/auth';\nimport { db, auth } from './firebase';\n\nexport function generateSlug(question: string): string {\n  return question\n    .toLowerCase()\n    .normalize('NFD')\n    .replace(/[\u0300-\u036f]/g, '')\n    .replace(/[^a-z0-9\\s-]/g, '')\n    .trim()\n    .replace(/\\s+/g, '-')\n    .slice(0, 80)\n    + '-' + Math.random().toString(36).slice(2, 7);\n}\n\nexport async function getPollBySlug(slug: string) {\n  const q = query(collection(db, 'polls'), where('slug', '==', slug));\n  const snap = await getDocs(q);\n  if (snap.empty) return null;\n  return { id: snap.docs[0].id, ...snap.docs[0].data() };\n}\n\nexport async function ensureAuth() {\n  if (!auth.currentUser) {\n    await signInAnonymously(auth);\n  }\n  return auth.currentUser!;\n}\n\nexport async function signInWithGoogle() {\n  const provider = new GoogleAuthProvider();\n  // Use redirect on mobile/when popup is blocked, popup on desktop\n  const isMobile = /iPhone|iPad|iPod|Android/i.test(navigator.userAgent);\n  if (isMobile) {\n    return signInWithRedirect(auth, provider);\n  }\n  return signInWithPopup(auth, provider);\n}\n\nexport async function getGoogleRedirectResult() {\n  return getRedirectResult(auth);\n}\n\nexport function subscribeToPolls(callback: (polls: any[]) => void) {\n  const q = query(collection(db, 'polls'), orderBy('createdAt', 'desc'));\n  return onSnapshot(q, (snap) => {\n    const polls = snap.docs.map((d, i) => ({ id: d.id, ...d.data(), _order: (d.data() as any).order ?? i }));\n    polls.sort((a, b) => a._order - b._order);\n    callback(polls);\n  });\n}\n\nexport async function getUserVotes(userId: string) {\n  const snap = await getDocs(collection(db, `users/${userId}/votes`));\n  const votes: Record<string, string> = {};\n  snap.forEach(d => { votes[d.id] = d.data().choice; });\n  return votes;\n}\n\nexport async function castVote(pollId: string, choice: string, userId: string, city?: string, isAnonymous?: boolean) {\n  await setDoc(doc(db, `users/${userId}/votes/${pollId}`), {\n    choice, votedAt: serverTimestamp(), city: city || null,\n  });\n  const field = choice === 'A' ? 'votesA' : 'votesB';\n  const cityField = city ? `cities.${city}.${choice === 'A' ? 'votesA' : 'votesB'}` : null;\n  const update: any = { [field]: increment(1), totalVotes: increment(1) };\n  if (cityField) update[cityField] = increment(1);\n  await updateDoc(doc(db, 'polls', pollId), update);\n  // Increment voteCount and votaCoins only for non-anonymous users\n  if (!isAnonymous) {\n    setDoc(doc(db, 'members', userId), {\n      voteCount: increment(1),\n      votaCoins: increment(1),\n    }, { merge: true }).catch(() => null);\n  }\n}\n\nexport async function createPoll({ question, optionA, optionB, tag, color, userId }: any) {\n  const snap = await getDocs(collection(db, 'polls'));\n  const lastOrder = snap.size;\n  return addDoc(collection(db, 'polls'), {\n    question, optionA, optionB, tag, color,\n    votesA: 0, votesB: 0, totalVotes: 0,\n    cities: {},\n    slug: generateSlug(question),\n    order: lastOrder,\n    createdBy: userId,\n    createdAt: serverTimestamp(),\n  });\n}\n\nexport async function seedPolls() {\n  const existing = await getDocs(collection(db, 'polls'));\n  if (!existing.empty) return;\n  const polls = [\n    { question: 'Voc\u00ea preferiria:', optionA: { emoji: '\ud83c\udf55', label: 'Pizza todo dia', sublabel: 'sem exce\u00e7\u00e3o' }, optionB: { emoji: '\ud83c\udf54', label: 'Hamb\u00farguer todo dia', sublabel: 'sem exce\u00e7\u00e3o' }, tag: 'comida', color: '#FF6B35', votesA: 6312, votesB: 3841 },\n    { question: 'Voc\u00ea aceitaria:', optionA: { emoji: '\ud83d\udcb0', label: 'R$1 milh\u00e3o agora', sublabel: 'mas sem voltar no tempo' }, optionB: { emoji: '\ud83d\udd50', label: 'Voltar aos 18', sublabel: 'sem dinheiro' }, tag: 'vida', color: '#6C63FF', votesA: 4521, votesB: 7893 },\n    { question: 'Quem \u00e9 maior?', optionA: { emoji: '\ud83d\udc10', label: 'Messi', sublabel: 'Argentina' }, optionB: { emoji: '\ud83d\udd34', label: 'Cristiano Ronaldo', sublabel: 'Portugal' }, tag: 'esporte', color: '#00C9A7', votesA: 14230, votesB: 12891 },\n    { question: 'Onde voc\u00ea moraria?', optionA: { emoji: '\ud83c\udfdd\ufe0f', label: 'Na praia', sublabel: 'calor e areia' }, optionB: { emoji: '\ud83c\udfd4\ufe0f', label: 'Na montanha', sublabel: 'frio e natureza' }, tag: 'estilo de vida', color: '#FF4E8C', votesA: 8943, votesB: 5612 },\n    { question: 'Voc\u00ea prefere:', optionA: { emoji: '\ud83c\udf19', label: 'Ser coruja', sublabel: 'dormir tarde' }, optionB: { emoji: '\u2600\ufe0f', label: 'Ser madrugador', sublabel: 'acordar cedo' }, tag: 'rotina', color: '#F7B731', votesA: 9871, votesB: 4320 },\n    { question: 'Se pudesse escolher:', optionA: { emoji: '\ud83e\uddb8', label: 'Voar', sublabel: 'sem limites' }, optionB: { emoji: '\ud83e\udde0', label: 'Ler mentes', sublabel: 'de qualquer pessoa' }, tag: 'superpoderes', color: '#FF5252', votesA: 11203, votesB: 9874 },\n  ];\n  for (const p of polls) {\n    await addDoc(collection(db, 'polls'), {\n      ...p, totalVotes: p.votesA + p.votesB, cities: {},\n      createdBy: 'system', createdAt: serverTimestamp(),\n    });\n  }\n}\n");
fs.writeFileSync("src/components/PollCard.tsx", "'use client';\nimport { useState } from 'react';\nimport { doc, setDoc, serverTimestamp } from 'firebase/firestore';\nimport { db } from '@/lib/firebase';\n\nfunction fmt(n: number) {\n  if (n >= 1000000) return (n / 1000000).toFixed(1) + 'M';\n  if (n >= 1000) return (n / 1000).toFixed(1) + 'k';\n  return String(n);\n}\n\nexport default function PollCard({ poll, onVote, userVote, userId, isFirstVote, onSubscribed, isAnon, onShowAuth }: {\n  poll: any;\n  onVote: (id: string, choice: string) => void;\n  userVote?: string;\n  userId?: string;\n  isFirstVote?: boolean;\n  onSubscribed?: () => void;\n  isAnon?: boolean;\n  onShowAuth?: () => void;\n}) {\n  const [hovering, setHovering] = useState<string | null>(null);\n  const [phone, setPhone] = useState('');\n  const [phoneSaved, setPhoneSaved] = useState(false);\n  const [savingPhone, setSavingPhone] = useState(false);\n\n  const voted = !!userVote;\n  const total = (poll.votesA || 0) + (poll.votesB || 0);\n  const pctA = total > 0 ? Math.round((poll.votesA / total) * 100) : 50;\n  const pctB = 100 - pctA;\n\n  const formatPhone = (v: string) => {\n    const digits = v.replace(/\\D/g, '').slice(0, 11);\n    if (digits.length <= 2) return digits;\n    if (digits.length <= 7) return `(${digits.slice(0,2)}) ${digits.slice(2)}`;\n    return `(${digits.slice(0,2)}) ${digits.slice(2,7)}-${digits.slice(7)}`;\n  };\n\n  const handleSavePhone = async () => {\n    const digits = phone.replace(/\\D/g, '');\n    if (digits.length < 10 || !userId) return;\n    setSavingPhone(true);\n    await setDoc(doc(db, 'subscribers', userId), {\n      phone: digits,\n      userId,\n      subscribedAt: serverTimestamp(),\n      active: true,\n    });\n    // Also save phone to members so it links to email account\n    await setDoc(doc(db, 'members', userId), { phone: digits }, { merge: true }).catch(() => null);\n    setPhoneSaved(true);\n    setSavingPhone(false);\n    if (onSubscribed) onSubscribed();\n  };\n\n  const options = [\n    { key: 'A', data: poll.optionA, pct: pctA, votes: poll.votesA || 0 },\n    { key: 'B', data: poll.optionB, pct: pctB, votes: poll.votesB || 0 },\n  ];\n\n  return (\n    <div\n      className=\"relative rounded-2xl p-6 mb-4 border transition-all duration-300\"\n      style={{\n        background: 'rgba(255,255,255,0.03)',\n        borderColor: voted ? poll.color + '33' : 'rgba(255,255,255,0.07)',\n      }}\n    >\n      {/* Pol\u00eamica do Dia banner */}\n      {poll.hotOfDay && (\n        <div\n          className=\"flex items-center gap-2 px-4 py-2 rounded-xl mb-3 text-xs font-black tracking-widest\"\n          style={{\n            background: 'linear-gradient(90deg, #FF4E8C22, #FF6B3522)',\n            border: '1px solid #FF4E8C44',\n          }}\n        >\n          <span className=\"text-base animate-pulse\">\ud83d\udd25</span>\n          <span style={{ background: 'linear-gradient(90deg, #FF4E8C, #FF6B35)', WebkitBackgroundClip: 'text', WebkitTextFillColor: 'transparent' }}>\n            POL\u00caMICA DO DIA\n          </span>\n        </div>\n      )}\n\n      {/* Tag */}\n      <div className=\"flex items-center gap-2 mb-4\">\n        <div\n          className=\"flex items-center gap-1.5 px-3 py-1 rounded-full text-xs font-bold tracking-widest uppercase border\"\n          style={{ color: poll.color, borderColor: poll.color + '44', background: poll.color + '11' }}\n        >\n          <span className=\"w-1.5 h-1.5 rounded-full\" style={{ background: poll.color }} />\n          {poll.tag}\n        </div>\n        {voted && (\n          <span className=\"ml-auto text-xs\" style={{ color: 'rgba(255,255,255,0.3)' }}>\n            {fmt(total)} votos\n          </span>\n        )}\n      </div>\n\n      {/* Question */}\n      <p className=\"text-sm mb-5\" style={{ color: 'rgba(255,255,255,0.4)', fontFamily: 'var(--font-body)' }}>\n        {poll.question}\n      </p>\n\n      {/* Options */}\n      <div className=\"space-y-3\">\n        {options.map(({ key, data, pct, votes }) => {\n          const isWinner = voted && pct > 50;\n          const isUserVote = userVote === key;\n          const isLoser = voted && !isUserVote;\n\n          return (\n            <button\n              key={key}\n              onClick={() => !voted && onVote(poll.id, key)}\n              onMouseEnter={() => !voted && setHovering(key)}\n              onMouseLeave={() => setHovering(null)}\n              disabled={voted}\n              className=\"relative w-full flex items-center gap-4 p-4 rounded-xl border-2 overflow-hidden transition-all duration-300 text-left\"\n              style={{\n                borderColor: isUserVote ? poll.color : hovering === key ? poll.color + '66' : 'rgba(255,255,255,0.08)',\n                background: isUserVote ? poll.color + '15' : hovering === key ? poll.color + '08' : 'rgba(255,255,255,0.03)',\n                opacity: isLoser ? 0.4 : 1,\n                cursor: voted ? 'default' : 'pointer',\n              }}\n            >\n              {voted && (\n                <div\n                  className=\"absolute inset-y-0 left-0 transition-all duration-700\"\n                  style={{\n                    width: `${pct}%`,\n                    background: isUserVote ? poll.color + '20' : 'rgba(255,255,255,0.03)',\n                  }}\n                />\n              )}\n              <span className=\"relative text-3xl\">{data.emoji}</span>\n              <div className=\"relative flex-1 min-w-0\">\n                <div className=\"font-bold text-white text-sm truncate\">{data.label}</div>\n                {data.sublabel && (\n                  <div className=\"text-xs mt-0.5\" style={{ color: 'rgba(255,255,255,0.35)' }}>{data.sublabel}</div>\n                )}\n              </div>\n              {voted ? (\n                <div className=\"relative text-right shrink-0\">\n                  <div className=\"text-xl font-black\" style={{ color: isUserVote ? poll.color : 'rgba(255,255,255,0.35)', fontFamily: 'var(--font-display)', letterSpacing: '0.05em' }}>\n                    {pct}%\n                  </div>\n                  <div className=\"text-xs\" style={{ color: 'rgba(255,255,255,0.25)' }}>{fmt(votes)}</div>\n                </div>\n              ) : (\n                <div\n                  className=\"relative w-7 h-7 rounded-full border-2 flex items-center justify-center text-xs font-bold shrink-0\"\n                  style={{ borderColor: 'rgba(255,255,255,0.15)', color: 'rgba(255,255,255,0.3)' }}\n                >\n                  {key}\n                </div>\n              )}\n            </button>\n          );\n        })}\n      </div>\n\n      {/* Footer ap\u00f3s votar */}\n      {voted && (\n        <div className=\"mt-4 pt-4 border-t\" style={{ borderColor: 'rgba(255,255,255,0.06)' }}>\n\n          {/* WhatsApp capture \u2014 s\u00f3 no primeiro voto, s\u00f3 para membros */}\n          {isAnon && onShowAuth && (\n            <div className=\"mt-3 p-3 rounded-2xl cursor-pointer active:scale-95 transition-transform\" onClick={onShowAuth}\n              style={{ background: 'linear-gradient(135deg, rgba(247,183,49,0.12), rgba(255,107,53,0.08))', border: '1px solid rgba(247,183,49,0.3)' }}>\n              <div className=\"flex items-center justify-between\">\n                <div>\n                  <p className=\"text-xs font-black\" style={{ color: '#F7B731' }}>\ud83c\udf81 Ganhe 50 VotaCoins de b\u00f4nus!</p>\n                  <p className=\"text-xs mt-0.5\" style={{ color: 'rgba(255,255,255,0.4)' }}>Crie sua conta agora \u00b7 +1 coin por voto \u00b7 Saque a partir de R$20</p>\n                </div>\n                <span className=\"text-lg ml-3\">\u2192</span>\n              </div>\n            </div>\n          )}\n          {isFirstVote && !phoneSaved && !isAnon && (\n            <div className=\"mb-3 p-3 rounded-xl\" style={{ background: 'rgba(37,211,102,0.07)', border: '1px solid #25D36622' }}>\n              <p className=\"text-xs font-black mb-2\" style={{ color: '#25D366' }}>\ud83d\udd25 Receba a Pol\u00eamica do Dia no WhatsApp</p>\n              <div className=\"flex gap-2\">\n                <div className=\"relative flex-1\">\n                  <span className=\"absolute left-3 top-1/2 -translate-y-1/2 text-xs font-bold\" style={{ color: 'rgba(255,255,255,0.3)' }}>+55</span>\n                  <input\n                    className=\"w-full rounded-lg pl-9 pr-3 py-2 text-xs text-white outline-none border\"\n                    style={{ background: 'rgba(255,255,255,0.05)', borderColor: 'rgba(255,255,255,0.1)' }}\n                    placeholder=\"(11) 99999-9999\"\n                    value={phone}\n                    onChange={e => setPhone(formatPhone(e.target.value))}\n                    inputMode=\"numeric\"\n                  />\n                </div>\n                <button\n                  onClick={handleSavePhone}\n                  disabled={phone.replace(/\\D/g,'').length < 10 || savingPhone}\n                  className=\"px-3 py-2 rounded-lg text-xs font-black shrink-0\"\n                  style={{\n                    background: phone.replace(/\\D/g,'').length >= 10 ? '#25D366' : 'rgba(255,255,255,0.07)',\n                    color: phone.replace(/\\D/g,'').length >= 10 ? 'white' : 'rgba(255,255,255,0.3)',\n                  }}\n                >\n                  {savingPhone ? '...' : 'Quero!'}\n                </button>\n              </div>\n            </div>\n          )}\n\n          {phoneSaved && (\n            <div className=\"mb-3 p-3 rounded-xl text-center\" style={{ background: 'rgba(37,211,102,0.07)', border: '1px solid #25D36622' }}>\n              <p className=\"text-xs font-black\" style={{ color: '#25D366' }}>\u2705 Cadastrado! Voc\u00ea vai receber a Pol\u00eamica do Dia \ud83d\udd25</p>\n            </div>\n          )}\n\n          <div className=\"flex items-center justify-between\">\n            <span className=\"text-xs\" style={{ color: 'rgba(255,255,255,0.25)' }}>\n              {userVote === 'A' ? poll.optionA.emoji : poll.optionB.emoji} Voc\u00ea votou em {userVote === 'A' ? poll.optionA.label : poll.optionB.label}\n            </span>\n            <button\n              onClick={() => {\n                const url = poll.slug ? `https://votaai.app/p/${poll.slug}` : 'https://votaai.app';\n                const text = `\ud83d\udd25 ${poll.question}\\n${poll.optionA.emoji} ${poll.optionA.label} ${pctA}% vs ${poll.optionB.emoji} ${poll.optionB.label} ${pctB}%\\n\\nResponda e ganhe VotaCoins! \ud83d\udc49 ${url}`;\n                if (navigator.share) navigator.share({ text });\n                else navigator.clipboard.writeText(text);\n              }}\n              className=\"text-xs px-3 py-1.5 rounded-lg border transition-colors\"\n              style={{ borderColor: 'rgba(255,255,255,0.1)', color: 'rgba(255,255,255,0.4)' }}\n            >\n              \ud83d\udce4 Compartilhar\n            </button>\n          </div>\n        </div>\n      )}\n    </div>\n  );\n}\n");
fs.writeFileSync("src/components/VotaCoin.tsx", "export default function VotaCoin({ size = 20 }: { size?: number }) {\n  return (\n    <svg width={size} height={size} viewBox=\"0 0 32 32\" fill=\"none\" xmlns=\"http://www.w3.org/2000/svg\">\n      <defs>\n        <radialGradient id=\"coinGold\" cx=\"38%\" cy=\"32%\" r=\"65%\">\n          <stop offset=\"0%\" stopColor=\"#FFF176\" />\n          <stop offset=\"35%\" stopColor=\"#FFD700\" />\n          <stop offset=\"70%\" stopColor=\"#F59E0B\" />\n          <stop offset=\"100%\" stopColor=\"#92400E\" />\n        </radialGradient>\n        <radialGradient id=\"coinShine\" cx=\"30%\" cy=\"25%\" r=\"45%\">\n          <stop offset=\"0%\" stopColor=\"white\" stopOpacity=\"0.6\" />\n          <stop offset=\"100%\" stopColor=\"white\" stopOpacity=\"0\" />\n        </radialGradient>\n        <filter id=\"coinShadow\">\n          <feDropShadow dx=\"0\" dy=\"2\" stdDeviation=\"2\" floodColor=\"#92400E\" floodOpacity=\"0.5\" />\n        </filter>\n      </defs>\n      {/* Shadow */}\n      <ellipse cx=\"16\" cy=\"18\" rx=\"12\" ry=\"3\" fill=\"rgba(0,0,0,0.3)\" />\n      {/* Coin body */}\n      <circle cx=\"16\" cy=\"15\" r=\"13\" fill=\"url(#coinGold)\" filter=\"url(#coinShadow)\" />\n      {/* Rim */}\n      <circle cx=\"16\" cy=\"15\" r=\"13\" fill=\"none\" stroke=\"#B45309\" strokeWidth=\"1\" />\n      {/* Inner ring */}\n      <circle cx=\"16\" cy=\"15\" r=\"10.5\" fill=\"none\" stroke=\"#FDE68A\" strokeWidth=\"0.7\" opacity=\"0.7\" />\n      {/* V$ text */}\n      <text x=\"16\" y=\"20.5\" textAnchor=\"middle\" fill=\"#7C2D12\" fontSize=\"9.5\" fontWeight=\"900\" fontFamily=\"Arial Black, Arial, sans-serif\">V$</text>\n      {/* Shine */}\n      <circle cx=\"16\" cy=\"15\" r=\"13\" fill=\"url(#coinShine)\" />\n    </svg>\n  );\n}\n");
